INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-09', E'시와 찬미 (시편 93장)', E'시편 93장', E'시편 93편은 "여호와께서 다스리시니"라는 장엄한 선언으로 시작됩니다. 이 짧은 시편은 하나님의 왕권에 대한 확고한 신앙고백을 담고 있습니다. 시인은 하나님께서 권위의 옷을 입으시고 능력의 띠를 띠셨다고 표현하는데, 이는 고대 근동에서 왕의 즉위식 때 왕복을 입는 모습을 연상시킵니다. 그러나 지상의 왕들과 달리 여호와의 왕권은 "예로부터" 견고히 섰으며, 그분은 "영원부터" 계셨다는 고백은 하나님의 통치가 시간을 초월한 영원한 것임을 보여줍니다.\n\n특별히 주목할 것은 3-4절에서 "큰 물"의 이미지가 반복해서 등장한다는 점입니다. 고대 근동 세계에서 바다와 큰 물은 혼돈과 파괴의 힘을 상징했습니다. 이스라엘 백성에게는 홍해를 건넌 기억과 함께, 주변 강대국들의 위협이 마치 거대한 파도처럼 밀려오는 현실을 떠올리게 했을 것입니다. 그러나 시인은 아무리 큰 물이 소리를 높이고 물결을 높여도, "높이 계신 여호와의 능력"이 그 모든 것보다 크다고 선포합니다. 이는 단순한 비교가 아니라, 하나님의 절대 주권에 대한 신앙고백입니다.\n\n시편의 마지막 절은 하나님의 말씀의 확실함과 성전의 거룩함으로 마무리됩니다. "주의 증거들이 매우 확실하고"라는 표현은 하나님의 약속과 계시가 흔들림 없이 신실하다는 의미입니다. 또한 "거룩함이 주의 집에 합당하다"는 고백은 영원하신 왕 앞에 나아가는 예배자의 합당한 자세를 보여줍니다. 세상의 혼돈과 위협 속에서도 하나님의 백성이 붙들어야 할 것은 바로 이것입니다 - 여호와께서 왕이시며, 그분의 통치는 영원하고, 그분의 말씀은 확실하며, 그분께 거룩함으로 나아가는 것이 우리의 응답이라는 진리입니다.', E'오늘의 핵심\n시인은 세상의 모든 혼돈과 위협을 압도하시는 여호와의 영원한 왕권을 선포하며, 그분의 확실한 말씀과 거룩하심 앞에 합당한 예배로 나아갈 것을 보여줍니다.\n\n묵상 질문\n1. 내 삶에서 ''큰 물''처럼 위협적으로 다가오는 것들은 무엇이며, 그것보다 크신 하나님의 능력을 어떻게 경험하고 있나요?\n2. 하나님의 왕 되심을 인정한다는 것이 일상생활에서 어떤 변화를 가져다주나요?\n3. 영원하신 하나님께 ''거룩함''으로 나아간다는 것은 구체적으로 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-10', E'시와 찬미 (시편 94장)', E'시편 94장', E'시편 94편은 악인의 횡포 앞에서 정의의 하나님을 간절히 부르짖는 시인의 기도를 담고 있습니다. "복수하시는 하나님이여 빛을 비추어 주소서"(94:1)라는 첫 구절은 불의한 현실 속에서 하나님의 공의로운 개입을 갈망하는 절박한 외침입니다.\n\n시인이 목격한 현실은 참담했습니다. 악인들이 하나님의 백성을 짓밟고, 과부와 나그네를 죽이며, 고아들을 살해하면서도 "여호와가 보지 못하며 야곱의 하나님이 알아차리지 못하리라"(94:7)고 조롱하고 있었습니다. 그들의 교만은 하늘을 찌를 듯했고, 의인들은 고통 속에 신음하고 있었습니다.\n\n그러나 시인은 절망하지 않습니다. 오히려 귀를 지으신 분이 어찌 듣지 못하시며, 눈을 만드신 분이 어찌 보지 못하시겠느냐고 반문합니다. 하나님께서는 사람의 헛된 생각을 아시고, 때가 되면 반드시 공의로운 심판을 행하실 것입니다. 시인은 이 확신 위에서 놀라운 고백으로 전환합니다. "여호와께서는 자기 백성을 버리지 아니하시며 자기의 소유를 외면하지 아니하시리로다"(94:14).\n\n특별히 주목할 것은 시인이 발견한 하나님의 교육 방법입니다. 하나님은 때로 징벌을 통해 당신의 백성을 교훈하시지만, 그것은 환난의 날을 피하게 하시려는 사랑의 훈련입니다. "나의 발이 미끄러진다고 말할 때에 주의 인자하심이 나를 붙드셨사오며"(94:18)라는 고백은 연약함 속에서도 붙드시는 하나님의 은혜를 경험한 자의 간증입니다.\n\n시편은 하나님께서 나의 요새이시며 피할 반석이라는 확신으로 마무리됩니다. 악인들의 죄악은 결국 그들에게로 되돌아갈 것이며, 하나님의 공의는 반드시 실현될 것입니다. 불의가 판치는 세상에서도 하나님의 백성이 소망을 잃지 않을 수 있는 이유가 여기에 있습니다.', E'오늘의 핵심\n시인은 악인의 횡포가 극심한 현실 속에서도 자기 백성을 버리지 않으시고 인자하심으로 붙드시는 하나님을 신뢰하며, 그분의 공의로운 심판을 확신합니다.\n\n묵상 질문\n1. 불의한 현실을 보며 "하나님이 정말 보고 계실까?" 의심했던 때가 있나요?\n2. 하나님의 징계나 훈련이 오히려 은혜였음을 깨달은 경험이 있으신가요?\n3. "발이 미끄러질 때" 하나님의 인자하심이 나를 붙드신 경험을 나눌 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-11', E'시와 찬미 (시편 95장)', E'시편 95장', E'시편 95편은 예배로의 부름과 경고가 절묘하게 어우러진 시입니다. 시인은 "오라"라는 초청으로 시작하여 하나님께 나아가 찬양하기를 권면합니다. 여기서 주목할 것은 단순히 개인적 예배가 아닌 "우리가"라는 공동체적 예배로의 부름입니다. 구원의 반석이신 하나님께 즐거이 외치고, 감사함으로 나아가며, 시를 지어 노래하라는 이 권면은 예배가 우리의 전 존재로 드리는 기쁨의 행위임을 보여줍니다.\n\n시인이 하나님을 찬양하는 이유는 분명합니다. 여호와는 모든 신들보다 크신 왕이시며, 땅의 깊은 곳부터 산들의 높은 곳까지, 바다와 육지 모든 것이 그분의 손 안에 있기 때문입니다. 창조주 하나님의 주권은 온 우주에 미치며, 그 어떤 것도 그분의 통치 밖에 있지 않습니다. 이러한 창조주 앞에서 피조물인 우리가 할 수 있는 합당한 반응은 경배와 무릎 꿇음입니다.\n\n그런데 시편은 7절을 기점으로 급격한 전환을 보입니다. "그는 우리의 하나님이시요 우리는 그가 기르시는 백성이며 그의 손이 돌보시는 양"이라는 친밀한 관계의 고백 다음에 "너희가 오늘 그의 음성을 듣거든"이라는 조건절이 등장합니다. 목자이신 하나님의 음성을 듣는 것은 양의 특권이자 책임입니다.\n\n시인은 광야에서의 므리바와 맛사 사건을 상기시키며 경고합니다. 출애굽의 놀라운 기적을 체험했으면서도 하나님을 시험하고 불신했던 조상들의 실패를 반복하지 말라는 것입니다. 40년 동안 광야를 떠돌며 안식에 들어가지 못했던 그들의 비극은 마음이 미혹되어 하나님의 길을 알지 못했기 때문이었습니다. 이 경고는 오늘날 우리에게도 동일하게 적용됩니다. 찬양과 예배의 자리에 있으면서도 마음이 완악해질 수 있다는 엄중한 가르침입니다.', E'오늘의 핵심\n시인은 창조주이시며 목자이신 하나님께 기쁨으로 예배하되, 광야에서 불신했던 조상들의 실패를 경계하며 오늘 그분의 음성에 순종할 것을 촉구합니다.\n\n묵상 질문\n1. 나는 하나님께 나아갈 때 감사함과 기쁨으로 가득한 마음인가요?\n2. 과거의 은혜를 체험하고도 현재의 시험 앞에서 불신하는 모습은 없나요?\n3. 오늘 내게 들려주시는 하나님의 음성은 무엇이며, 어떻게 응답하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-12', E'시와 찬미 (시편 96장)', E'시편 96장', E'시편 96편은 "새 노래로 여호와께 노래하라"는 힘찬 선언으로 시작됩니다. 이 찬양의 초대는 단순히 이스라엘 백성만이 아닌 ''온 땅''을 향한 것입니다. 시인은 하나님의 구원을 날마다 전파하고, 그의 영광과 기이한 행적을 만민 가운데 선포하라고 권면합니다.\n\n특별히 시인은 여호와를 "모든 신들보다 경외할 것"(96:4)이라고 선포하면서, 만국의 모든 신들은 우상에 불과하지만 여호와는 하늘을 지으신 창조주임을 분명히 합니다. 이는 고대 근동 세계에서 각 민족이 자신들의 신을 섬기던 상황에서, 오직 여호와만이 참된 하나님이심을 담대히 선언하는 것입니다.\n\n시편 기자는 하나님의 성소에 있는 "능력과 아름다움"을 묘사하며, 만국의 족속들이 예물을 들고 그 궁정에 들어와 예배할 것을 초청합니다. 여기서 주목할 점은 예배가 단지 말로만 드리는 것이 아니라, 구체적인 헌신과 예물로 표현되어야 함을 보여준다는 것입니다.\n\n이 시편의 절정은 온 피조세계가 함께 기뻐하며 찬양하는 장면입니다. 하늘과 땅, 바다와 들판, 심지어 숲의 나무들까지도 여호와 앞에서 즐거이 노래합니다. 이는 하나님의 통치가 단지 인간 세계에만 국한되지 않고 모든 피조물에게 미치는 우주적 통치임을 보여줍니다.\n\n시편은 "그가 의로 세계를 심판하시며 그의 진실하심으로 백성을 심판하시리로다"(96:13)라는 선언으로 마무리됩니다. 여기서 심판은 단순한 정죄가 아니라, 왜곡된 것을 바로잡고 정의를 세우시는 하나님의 통치 행위입니다. 이 공의로운 심판에 대한 기대가 오히려 피조물들에게 기쁨과 찬양의 이유가 되는 것은, 하나님의 심판이 곧 구원과 회복을 의미하기 때문입니다.', E'오늘의 핵심\n시편 96편은 온 땅과 만민이 창조주 하나님께 새 노래로 찬양하며, 그분의 의로운 통치를 기뻐하도록 초대하는 우주적 예배의 부름입니다.\n\n묵상 질문\n1. 우리가 하나님께 ''새 노래''로 찬양해야 하는 이유는 무엇일까요?\n2. 만국의 신들과 달리 여호와만이 경배받으셔야 하는 근거는 무엇인가요?\n3. 하나님의 심판이 두려움이 아닌 기쁨의 이유가 되는 것을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-14', E'시와 찬미 (시편 103장)', E'시편 103장', E'다윗은 자신의 영혼을 향해 명령합니다. "내 영혼아 여호와를 송축하라." 이 시편은 개인적이고 내밀한 고백으로 시작되지만, 점차 온 우주를 아우르는 거대한 찬양으로 확대됩니다. 무엇이 시인으로 하여금 이토록 간절하게 하나님을 찬양하도록 만들었을까요?\n\n다윗은 먼저 하나님께서 베푸신 개인적인 은혜들을 하나씩 헤아립니다. 모든 죄악을 사하시고, 모든 병을 고치시며, 생명을 파멸에서 속량하시는 하나님. 특별히 "동이 서에서 먼 것 같이 우리의 죄과를 우리에게서 멀리 옮기셨으며"(12절)라는 고백은 하나님의 용서가 얼마나 완전한지를 보여줍니다. 동쪽과 서쪽은 결코 만날 수 없는 무한한 거리입니다. 하나님은 우리의 죄를 그토록 멀리, 완전히 제거하십니다.\n\n더 놀라운 것은 하나님께서 우리를 이해하신다는 사실입니다. "이는 그가 우리의 체질을 아시며 우리가 단지 먼지뿐임을 기억하심이로다"(14절). 하나님은 우리가 연약한 존재임을 아십니다. 풀처럼 시들고, 꽃처럼 사라지는 존재임을 아시면서도, 아버지가 자식을 긍휼히 여기듯 우리를 품어주십니다. 이것이 바로 하나님의 인자하심입니다.\n\n시편의 후반부로 가면서 찬양의 범위는 더욱 확장됩니다. 하늘의 천사들, 모든 천군, 그리고 하나님이 지으신 모든 피조물이 찬양의 대열에 합류합니다. 개인의 고백으로 시작된 찬양이 우주적 교향곡이 되는 것입니다. \n\n웨슬리는 이 시편을 읽으며 하나님의 선행은총을 보았습니다. 우리가 먼지 같은 존재임에도 불구하고 먼저 사랑하시고, 용서하시고, 회복시키시는 하나님의 은혜가 바로 찬양의 근거가 됩니다. 우리의 찬양은 단순한 의무가 아니라, 은혜에 대한 자연스러운 응답입니다. 오늘도 "내 영혼아 여호와를 송축하라"는 다윗의 외침이 우리의 고백이 되기를 소망합니다.', E'오늘의 핵심\n하나님은 우리의 연약함을 아시면서도 완전한 용서와 회복을 베푸시는 분이시며, 이러한 은혜를 깨달은 영혼은 자연스럽게 찬양으로 응답하게 됩니다.\n\n묵상 질문\n1. 하나님의 모든 은택을 잊지 말라는 다윗의 권면처럼, 오늘 내가 기억하고 감사해야 할 하나님의 은혜는 무엇입니까?\n2. 하나님께서 내 죄를 동이 서에서 먼 것처럼 완전히 옮기셨다는 사실을 믿습니까? 아직도 과거의 죄책감에서 자유하지 못한 부분이 있다면 무엇입니까?\n3. 내가 먼지와 같이 연약한 존재임을 인정하면서도, 하나님 아버지의 긍휼하심을 신뢰할 때 내 삶과 기도는 어떻게 변화될까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-15', E'시와 찬미 (시편 104장)', E'시편 104장', E'시편 104편은 창조주 하나님의 위대하심을 장엄하게 노래하는 찬양시입니다. "내 영혼아 여호와를 송축하라"는 외침으로 시작하는 이 시는, 창조 세계 구석구석에 새겨진 하나님의 지혜와 능력을 세밀하게 그려냅니다.\n\n시인은 먼저 하나님께서 빛을 옷처럼 입으시고 하늘을 휘장같이 펼치신 모습을 묘사합니다. 구름을 수레 삼아 바람 날개로 다니시는 창조주의 위엄이 눈앞에 펼쳐집니다. 특히 인상적인 것은 창조의 질서입니다. 하나님께서는 물의 경계를 정하여 다시는 땅을 덮지 못하게 하셨고, 샘물이 골짜기에서 솟아 산 사이로 흐르게 하셔서 모든 생명체가 생존할 수 있도록 섬세하게 설계하셨습니다.\n\n시인의 시선은 미시적인 것에서 거시적인 것으로, 작은 생명체에서 광활한 바다까지 자유롭게 이동합니다. 들나귀가 목마름을 해결하고, 새들이 나뭇가지에서 지저귀며, 산양이 높은 산을 뛰어다니고, 너구리가 바위틈에 은신하는 모습까지 - 하나님께서는 각 피조물에게 필요한 서식지와 양식을 완벽하게 제공하십니다. "주께서 주신즉 그들이 받으며 주께서 손을 펴신즉 그들이 좋은 것으로 만족하다가"(28절)라는 고백처럼, 모든 생명은 하나님의 손에서 나오는 일용할 양식으로 살아갑니다.\n\n특별히 이 시편은 인간의 노동도 창조 질서의 일부로 봅니다. 밤에는 들짐승이 활동하고 낮에는 인간이 일하는 리듬, 포도주와 기름과 양식으로 기쁨과 힘을 얻는 일상의 은혜가 모두 하나님의 선물입니다. 시인은 이 모든 것을 관찰하며 감탄합니다: "여호와여 주께서 하신 일이 어찌 그리 많은지요!"\n\n이 찬양시는 단순한 자연 예찬이 아닙니다. 피조물의 생명이 전적으로 창조주의 호흡에 달려 있음을 깊이 인식하는 신앙고백입니다. 주께서 호흡을 거두시면 모든 것이 먼지로 돌아가지만, 주의 영을 보내시면 다시 창조되어 지면이 새로워집니다. 그래서 시인은 "내가 평생토록 여호와께 노래하며 내가 살아 있는 동안 내 하나님을 찬양하리로다"라고 결단합니다. 창조의 신비를 깊이 묵상할 때, 우리의 입술에서도 이런 찬양이 터져 나올 수밖에 없습니다.', E'오늘의 핵심\n창조 세계의 경이로움을 깊이 관찰하고 묵상할 때, 우리는 모든 생명의 근원이신 하나님의 지혜와 사랑을 발견하며 평생 찬양할 수밖에 없는 존재임을 깨닫게 됩니다.\n\n묵상 질문\n1. 일상에서 마주하는 자연의 섭리를 통해 창조주 하나님의 손길을 발견한 경험이 있습니까?\n2. 내 생명과 호흡이 전적으로 하나님께 달려 있음을 인식할 때, 오늘 하루를 어떻게 살아가야 할까요?\n3. 창조의 아름다움 속에서도 죄와 악이 존재하는 현실을 어떻게 이해하고, 새 창조를 향한 소망을 품을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-16', E'시와 찬미 (시편 105장)', E'시편 105장', E'시편 105편은 "여호와께 감사하고 그의 이름을 불러 아뢰며"로 시작하는 역사 회고의 찬양시입니다. 시인은 아브라함부터 출애굽까지 이스라엘의 역사를 되짚으며 하나님께서 어떻게 언약을 지키셨는지를 노래합니다. 이 시편의 가장 중요한 주제는 8절에 나타납니다. "그는 그의 언약 곧 천 대에 걸쳐 명령하신 말씀을 영원히 기억하셨으니." 하나님은 한 번 맺으신 언약을 결코 잊지 않으시는 분입니다.\n\n시인은 먼저 아브라함과 이삭, 야곱에게 주신 언약을 기억합니다. 그들이 가나안 땅에서 나그네로 떠돌아다닐 때, 사람 수가 적어 연약했을 때에도 하나님은 그들을 보호하셨습니다. "나의 기름 부은 자를 손대지 말며 나의 선지자들을 해하지 말라"(15절)고 왕들을 꾸짖으며 그들을 지키셨습니다. 기근의 때에는 요셉을 먼저 애굽으로 보내어 구원의 길을 예비하셨습니다. 요셉이 종으로 팔려가고 옥에 갇힌 것조차도 하나님의 섭리 가운데 있었습니다.\n\n출애굽 사건은 하나님의 언약 성취의 절정을 보여줍니다. 시인은 열 가지 재앙을 차례로 언급하면서 하나님께서 어떻게 강력한 애굽을 꺾으시고 자기 백성을 구원하셨는지를 생생하게 그려냅니다. 흑암과 피, 개구리와 이, 우박과 메뚜기, 그리고 장자의 죽음까지 - 이 모든 것은 하나님께서 자기 백성을 위해 싸우시는 전쟁이었습니다. 마침내 이스라엘은 은금을 가지고 당당히 애굽을 떠났고, 광야에서도 구름기둥과 불기둥, 메추라기와 만나로 인도하시고 먹이셨습니다.\n\n시인은 이 모든 일이 "그의 거룩한 말씀과 그의 종 아브라함을 기억하셨음이로다"(42절)라고 결론짓습니다. 430년이라는 긴 세월이 흘렀지만 하나님은 아브라함에게 하신 약속을 잊지 않으셨습니다. 그리고 이 언약의 성취에는 목적이 있었습니다. "이는 그들이 그의 율례를 지키고 그의 율법을 따르게 하려 하심이로다"(45절). 구원받은 백성은 하나님의 뜻대로 살아야 할 책임이 있습니다. 역사를 기억하는 것은 단순한 회고가 아니라 오늘 우리가 어떻게 살아야 할지를 깨닫게 하는 거울입니다.', E'오늘의 핵심\n하나님은 천 대에 걸쳐 명령하신 언약을 영원히 기억하시며, 연약한 백성을 보호하시고 인도하셔서 마침내 약속의 땅으로 이끄신 신실하신 분입니다.\n\n묵상 질문\n1. 내 삶의 역사 속에서 하나님이 지키신 약속들을 구체적으로 기억하고 있습니까? 그 기억이 오늘의 믿음에 어떤 영향을 미치고 있나요?\n2. 요셉처럼 고난의 시간이 오히려 하나님의 계획을 이루는 과정임을 믿고 인내할 수 있습니까?\n3. 하나님의 구원을 경험한 백성으로서, 나는 그분의 율례와 율법을 따르는 삶을 살고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-17', E'시와 찬미 (시편 106장)', E'시편 106장', E'할렐루야로 시작하고 할렐루야로 끝나는 시편 106편은 이스라엘의 실패의 역사를 돌아보면서도 끊임없는 하나님의 인자하심을 고백하는 참회와 찬양의 시입니다. 시인은 "우리가 우리의 조상들처럼 범죄하여 사악을 행하며 악을 지었나이다"(6절)라고 고백하며, 출애굽부터 가나안 정착까지 이어진 불순종의 역사를 낱낱이 드러냅니다.\n\n홍해에서의 거역부터 시작하여 광야에서의 욕심, 모세와 아론에 대한 질투, 금송아지 숭배, 약속의 땅에 대한 불신앙, 바알과의 연합, 가나안 민족과의 혼합에 이르기까지 이스라엘의 반역은 끝이 없었습니다. 특히 "무죄한 피 곧 그들의 자녀의 피를 흘려 가나안의 우상들에게 제사하므로"(38절)라는 구절은 그들의 타락이 얼마나 깊은 지경에 이르렀는지를 보여줍니다.\n\n그러나 이 시편의 놀라운 점은 각각의 실패 이후에 반복되는 하나님의 구원 이야기입니다. 백성이 홍해에서 거역했을 때도 하나님은 자기 이름을 위하여 구원하셨고, 모세의 중재로 멸망을 돌이키셨으며, 비느하스의 헌신으로 재앙을 그치게 하셨습니다. 무엇보다 "여호와께서 그들의 부르짖음을 들으실 때에 그들의 고통을 돌보시며 그들을 위하여 그의 언약을 기억하시고"(44-45절)라는 고백은 하나님의 신실하심이 인간의 불신실함을 초월함을 보여줍니다.\n\n시인은 이스라엘의 실패를 남의 이야기로 전하지 않습니다. "우리가" 범죄했다는 고백으로 시작하여, "우리를 구원하사"라는 간구로 마칩니다. 과거의 실패를 직시하되 절망하지 않는 것은, 언약을 기억하시고 인자하심을 거두지 않으시는 하나님을 알기 때문입니다. 실패의 역사 속에서도 변함없이 역사하시는 하나님의 은혜를 발견할 때, 우리는 진정한 할렐루야를 부를 수 있습니다.', E'오늘의 핵심\n이스라엘의 끊임없는 실패와 반역의 역사 속에서도 하나님은 언약을 기억하시고 인자하심으로 구원하셨으며, 이러한 하나님의 신실하심이 우리로 하여금 참회와 찬양을 동시에 올릴 수 있게 합니다.\n\n묵상 질문\n1. 나의 신앙 여정에서 반복되는 실패의 패턴은 무엇이며, 그때마다 하나님은 어떤 방법으로 나를 회복시키셨나요?\n2. 과거의 죄와 실패를 기억할 때 수치심에 머물지 않고 하나님의 은혜로 나아가기 위해 무엇이 필요할까요?\n3. "그의 언약을 기억하시고"라는 말씀처럼, 내가 붙들어야 할 하나님의 약속은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-18', E'시와 찬미 (시편 135장)', E'시편 135장', E'시편 135편은 "할렐루야"로 시작하여 "할렐루야"로 끝나는 완전한 찬양의 시입니다. 성전 뜰에 서 있는 여호와의 종들을 향해 시편 기자는 찬송하라고 거듭 권면합니다. 그 이유는 분명합니다. "여호와는 선하시며 그의 이름이 아름다우니"(3절). 하나님의 선하심과 아름다우심은 찬양받기에 합당한 본질적 속성입니다.\n\n시편 기자는 이스라엘을 "자기의 특별한 소유"(4절)로 택하신 하나님의 주권적 사랑을 노래합니다. 이는 단순한 선택이 아니라 언약 관계 속에서 백성을 자신의 보물처럼 여기시는 하나님의 마음을 보여줍니다. 그리고 5절부터는 창조주 하나님의 위대하심이 펼쳐집니다. 천지와 바다와 모든 깊은 곳에서 기뻐하시는 일을 다 행하시는 분, 자연 현상을 주관하시며 역사를 이끄시는 분이 바로 여호와이십니다.\n\n특히 8절부터 12절까지는 출애굽과 가나안 정착의 역사를 압축적으로 보여줍니다. 애굽의 처음 난 자들을 치시고, 바로와 그의 신하들에게 표적을 행하시며, 시혼과 옥 같은 강대한 왕들을 무너뜨리신 하나님. 이 모든 일은 자기 백성에게 약속의 땅을 기업으로 주시려는 하나님의 신실하심에서 비롯되었습니다.\n\n그런데 15절부터는 날카로운 대조가 나타납니다. "열국의 우상은 은금이요 사람의 손으로 만든 것이라." 입이 있어도 말하지 못하고, 눈이 있어도 보지 못하며, 귀가 있어도 듣지 못하는 우상들. 더욱 경고하는 것은 18절입니다. "그것을 만든 자와 그것을 의지하는 자가 다 그것과 같으리로다." 생명 없는 우상을 의지하는 자는 결국 그 우상처럼 영적으로 무감각해진다는 뜻입니다.\n\n오늘날 우리가 의지하는 현대의 우상들은 무엇일까요? 재물, 명예, 인간관계, 혹은 자신의 능력일 수 있습니다. 이것들은 우리에게 진정한 생명을 줄 수 없으며, 오히려 하나님을 향한 우리의 영적 감각을 무디게 만듭니다. 시편은 다시 한번 외칩니다. 이스라엘 족속, 아론의 족속, 레위 족속, 그리고 여호와를 경외하는 모든 이들이여, 여호와를 송축하라고. 예루살렘에 계시고 시온에서 찬송받으실 분은 오직 살아계신 하나님뿐이십니다.', E'오늘의 핵심\n하나님은 천지를 다스리시고 자기 백성을 특별한 소유로 삼으신 살아계신 주님이시며, 생명 없는 우상과는 완전히 다른 찬양받기 합당한 분이십니다.\n\n묵상 질문\n1. 하나님이 나를 "특별한 소유"로 여기신다는 사실이 내 삶에 어떤 의미를 주나요?\n2. 내가 무의식적으로 의지하고 있는 현대의 우상들은 무엇인가요?\n3. 오늘 하나님의 어떤 속성과 행하신 일을 기억하며 찬양드리고 싶으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-19', E'시와 찬미 (시편 136장)', E'시편 136장', E'시편 136편은 "그 인자하심이 영원함이로다"라는 후렴구를 26번이나 반복하며 하나님의 변함없는 사랑을 노래하는 특별한 찬양시입니다. 이 시편은 유대인들의 대표적인 절기 예배에서 회중이 교독하며 부르던 것으로, 한 사람이 하나님의 행하신 일을 선포하면 회중이 "그 인자하심이 영원함이로다"라고 화답하는 방식으로 진행되었습니다.\n\n시인은 먼저 창조의 하나님을 찬양합니다. 지혜로 하늘을 지으시고 땅을 물 위에 펴시며, 해와 달과 별들로 낮과 밤을 주관하게 하신 창조주 하나님의 위대하심을 노래합니다. 그런데 주목할 것은 이 웅장한 창조 역사가 단순한 능력의 과시가 아니라 하나님의 인자하심, 곧 그분의 사랑에서 비롯되었다는 고백입니다. 온 우주를 지으신 그 손길에 우리를 향한 사랑이 담겨 있었던 것입니다.\n\n이어서 시인은 출애굽과 광야의 역사로 시선을 돌립니다. 애굽의 장자를 치시고, 홍해를 가르시며, 바로의 군대를 물에 빠뜨리신 일들을 기억합니다. 또한 광야에서 이스라엘을 인도하시고, 시혼과 옥 같은 강대한 왕들을 물리치시며, 약속의 땅을 기업으로 주신 구원의 역사를 회상합니다. 이 모든 구원의 행적 또한 하나님의 영원한 인자하심의 표현이었습니다.\n\n특별히 감동적인 것은 23절의 고백입니다. "우리를 비천한 가운데에서도 기억해 주신 이에게 감사하라." 하나님의 인자하심은 우리가 높은 곳에 있을 때만이 아니라 가장 낮고 비천한 자리에 있을 때도 우리를 잊지 않으십니다. 우리의 상황이 어떠하든, 우리의 형편이 어떠하든, 그분의 사랑은 변함이 없습니다.\n\n이 시편이 우리에게 가르쳐주는 것은 감사의 근거입니다. 우리의 감사는 변하는 환경이나 일시적인 축복에 기초하지 않고, 영원히 변치 않는 하나님의 인자하심에 뿌리를 두어야 합니다. 창조부터 구원, 그리고 일용할 양식을 주시는 일상의 은혜에 이르기까지, 하나님의 모든 행위는 그분의 영원한 사랑에서 흘러나옵니다. 오늘도 이 영원한 진리를 마음에 새기며 "그 인자하심이 영원함이로다"라고 고백할 수 있기를 바랍니다.', E'오늘의 핵심\n하나님의 창조와 구원의 모든 행위는 영원한 인자하심에서 비롯되며, 우리가 비천한 중에 있을 때도 그 사랑은 변함이 없습니다.\n\n묵상 질문\n1. 내 삶의 어떤 영역에서 하나님의 영원한 인자하심을 경험하고 있나요?\n2. 환경이 어려울 때도 변치 않는 하나님의 사랑을 신뢰하고 있나요?\n3. 오늘 "그 인자하심이 영원함이로다"라고 고백할 구체적인 이유는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-21', E'시와 찬미 (시편 137장)', E'시편 137장', E'바벨론 포로기의 깊은 상처를 담아낸 시편 137편은 이스라엘 백성의 가슴 아픈 탄식을 생생하게 전해줍니다. 기원전 586년, 예루살렘이 바벨론에 함락되고 수많은 백성이 끌려간 그 절망의 시간을 시인은 "바벨론의 여러 강변 거기에 앉아서 시온을 기억하며 울었도다"라고 표현합니다. 그들의 수금은 버드나무에 걸려 있습니다. 찬양의 악기가 침묵하게 된 것입니다.\n\n더 잔인한 것은 포로로 잡은 자들이 "시온의 노래 중 하나를 노래하라"고 요구한다는 점입니다. 성전에서 하나님께 올려드리던 거룩한 찬양을 이방 땅에서 구경거리로 부르라는 것입니다. 이에 시인은 절규합니다. "우리가 이방 땅에서 어찌 여호와의 노래를 부를까." 이것은 단순한 향수병이 아닙니다. 하나님의 임재가 있던 예루살렘 성전을 떠나 이방 땅에서 어떻게 예배할 수 있겠느냐는 신앙적 고뇌입니다.\n\n그런데 시인은 절망 속에서도 예루살렘을 잊지 않겠다고 맹세합니다. "내가 너를 잊을진대 내 오른손이 그의 재주를 잊을지로다." 오른손은 수금을 연주하는 손입니다. 예루살렘을 잊느니 차라리 다시는 연주하지 못하게 되기를 원한다는 것입니다. 이는 단순히 고향에 대한 그리움을 넘어, 하나님의 약속과 언약에 대한 신실한 붙듦을 보여줍니다.\n\n시편의 후반부는 에돔과 바벨론에 대한 저주로 가득합니다. 특히 마지막 구절은 현대인의 감각으로는 받아들이기 어려운 잔혹함을 담고 있습니다. 그러나 이는 복수심의 표현이라기보다 하나님의 공의에 대한 간절한 호소입니다. 악을 심판하시는 하나님께 자신들이 당한 고통을 있는 그대로 쏟아내는 것입니다.\n\n이 시편은 신앙의 여정에서 만나는 깊은 골짜기의 순간들을 보여줍니다. 찬양할 수 없을 만큼 아픈 시간, 하나님이 멀게만 느껴지는 순간에도 우리는 그분을 향한 기억을 놓지 않아야 합니다. 때로는 수금을 버드나무에 걸고 울 수밖에 없지만, 그 눈물조차 하나님을 향한 간절함의 표현이 될 수 있습니다.', E'오늘의 핵심\n포로 된 백성의 탄식은 단순한 향수가 아니라 하나님과의 관계를 그리워하는 신앙적 아픔이며, 절망 속에서도 하나님의 약속을 붙드는 것이 믿음의 본질입니다.\n\n묵상 질문\n1. 내 삶에서 ''수금을 버드나무에 걸어놓고'' 찬양할 수 없었던 때는 언제였나요?\n2. 고통 속에서도 하나님을 기억하고 붙들었던 경험이 있으신가요?\n3. 지금 내게 필요한 것은 새로운 찬양일까요, 아니면 눈물의 기도일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-22', E'시와 찬미 (시편 138장)', E'시편 138장', E'다윗은 "내가 전심으로 주께 감사하며"라는 고백으로 이 시편을 시작합니다. 여기서 ''전심으로''라는 표현은 마음의 일부가 아닌 존재 전체를 다해 하나님께 감사한다는 의미입니다. 특별히 그는 "신들 앞에서" 여호와를 찬송한다고 선언하는데, 이는 당시 이방 민족들이 섬기던 수많은 신들과는 비교할 수 없는 참 하나님께 대한 확고한 신앙고백입니다.\n\n다윗이 하나님께 감사하는 이유는 분명합니다. "내가 간구하는 날에 주께서 응답하시고 내 영혼에 힘을 주어 나를 강하게 하셨나이다"(3절). 기도에 응답하시는 하나님, 연약한 영혼에 힘을 불어넣어 주시는 하나님을 경험했기 때문입니다. 이것은 막연한 종교적 감정이 아니라 실제적인 만남에서 나온 고백입니다.\n\n더 나아가 다윗은 개인적 체험을 넘어 우주적 차원의 찬양을 노래합니다. 세상의 모든 왕들이 하나님의 말씀을 듣고 여호와의 도를 노래할 것이라고 선포합니다. 그 이유는 "여호와의 영광이 크심"이기 때문입니다. 높이 계신 하나님께서 낮은 자를 굽어살피시고, 멀리서도 교만한 자를 아신다는 것은 하나님의 초월성과 내재성을 동시에 보여줍니다.\n\n특히 주목할 만한 것은 7절의 고백입니다. "내가 환난 중에 다닐지라도 주께서 나를 살아나게 하시고." 다윗의 감사는 모든 문제가 해결된 후의 감사가 아닙니다. 여전히 환난 중에 있고, 원수들의 분노가 실재하는 상황에서도 그는 하나님의 구원을 확신합니다. 이는 과거의 응답 경험(3절)이 현재의 환난 속에서도 살아있는 신뢰가 되었음을 보여줍니다.\n\n시편의 마지막은 간절한 기도로 마무리됩니다. "주의 손으로 지으신 것을 버리지 마옵소서." 이는 단순한 애원이 아니라 하나님의 인자하심이 영원하다는 확신에 근거한 담대한 간구입니다. 창조주 하나님께서 당신의 작품인 우리를 끝까지 책임지실 것이라는 믿음의 고백입니다.', E'오늘의 핵심\n기도에 응답하시고 영혼에 힘을 주시는 하나님을 경험한 사람은 환난 중에서도 전심으로 감사하며, 하나님의 영원한 인자하심을 신뢰할 수 있습니다.\n\n묵상 질문\n1. 나는 지금 전심으로 하나님께 감사하고 있나요, 아니면 마음의 일부만 드리고 있나요?\n2. 과거에 경험한 하나님의 응답이 현재의 어려움 속에서도 살아있는 확신이 되고 있나요?\n3. "주의 손으로 지으신 것을 버리지 마옵소서"라는 다윗의 기도가 오늘 내게 어떤 위로를 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-23', E'시와 찬미 (시편 139장)', E'시편 139장', E'시편 139편은 하나님의 전지전능하심과 편재하심을 가장 아름답게 표현한 시편 중 하나입니다. 다윗은 하나님께서 자신을 완전히 아신다는 고백으로 시작합니다. 앉고 일어서는 일상의 모든 순간, 멀리서도 꿰뚫어 보시는 생각들, 아직 입 밖에 내지 않은 말까지도 하나님께서는 다 아십니다. 이런 전지하신 하나님의 지식 앞에서 다윗은 "이 지식이 내게 너무 기이하니 높아서 내가 능히 미치지 못하나이다"라고 감탄합니다.\n\n그런데 이어지는 고백이 더욱 놀랍습니다. 하늘 끝에서 스올까지, 새벽 날개를 치며 바다 끝에 가도 거기에도 하나님이 계신다는 것입니다. 어둠조차도 하나님을 가릴 수 없으며, 밤이 낮과 같이 비춥니다. 이는 단순히 하나님께서 모든 곳에 계신다는 교리적 설명이 아닙니다. 오히려 우리가 도망가고 싶을 때도, 숨고 싶을 때도 하나님의 손길이 우리를 인도하시고 붙드신다는 위로의 메시지입니다.\n\n특히 감동적인 것은 13절부터 이어지는 창조의 신비입니다. 하나님께서 어머니 뱃속에서 우리의 내장을 지으시고, 은밀한 곳에서 우리를 만드셨습니다. 더 놀라운 것은 우리가 태어나기도 전에 이미 하나님의 책에 우리의 모든 날들이 기록되어 있다는 사실입니다. 이는 운명론적 결정론이 아니라, 하나님께서 우리 각자를 향한 특별한 계획과 목적을 가지고 계신다는 선한 섭리의 고백입니다.\n\n시편의 후반부에서 다윗은 악인을 향한 거룩한 분노를 표현하면서도, 결국 자기 자신을 돌아봅니다. "하나님이여 나를 살피사 내 마음을 아시며"라는 기도로 돌아오는 것입니다. 남을 판단하기 전에 먼저 자신의 내면을 하나님께 열어드리는 겸손함이 여기 있습니다. 그리고 영원한 길로 인도해 달라는 간구로 시편을 마칩니다.\n\n오늘 우리도 이런 하나님 앞에 서 있습니다. 우리의 모든 것을 아시면서도 사랑하시는 하나님, 우리가 피하려 해도 끝까지 따라오시는 하나님, 태어나기 전부터 우리를 아시고 계획하신 하나님 앞에 있습니다. 이 사실이 때로는 부담스러울 수도 있지만, 동시에 가장 큰 위로가 됩니다. 내가 나를 포기해도 하나님은 나를 포기하지 않으시기 때문입니다.', E'오늘의 핵심\n하나님께서는 우리의 모든 것을 아시고, 어디에서도 함께하시며, 태어나기 전부터 우리를 향한 특별한 계획을 가지고 계십니다. 이 전능하신 사랑 앞에서 우리는 겸손히 자신을 돌아보며 영원한 길로 인도받기를 구해야 합니다.\n\n묵상 질문\n1. 하나님께서 나의 모든 것을 아신다는 사실이 위로가 되나요, 아니면 부담이 되나요?\n2. 내가 하나님을 피해 숨고 싶었던 때는 언제였나요? 그때도 하나님은 거기 계셨나요?\n3. 하나님께서 나를 지으신 목적과 계획이 무엇일지 기도하며 묵상해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-24', E'시와 찬미 (시편 140장)', E'시편 140장', E'시편 140편은 악인의 위협 속에서 하나님의 보호를 간구하는 다윗의 절박한 기도입니다. "여호와여 악인에게서 나를 건지시며 포악한 자에게서 나를 보전하소서"(시 140:1)로 시작되는 이 시편은 구체적이고 생생한 표현으로 원수들의 모습을 묘사합니다. 뱀처럼 날카로운 혀, 독사의 독이 있는 입술, 올무와 그물과 함정을 놓는 교만한 자들의 모습은 다윗이 직면한 위협이 얼마나 실제적이고 치명적이었는지를 보여줍니다.\n\n그러나 이 시편의 진정한 힘은 6절부터 나타나는 신앙고백에 있습니다. "주는 나의 하나님이시니"라는 선언과 함께 다윗은 하나님을 "내 구원의 능력"이라 부르며, 전쟁의 날에 자신의 머리를 가려주신 분으로 고백합니다. 이는 단순한 관념적 믿음이 아니라 실제 삶의 위기 속에서 경험한 하나님의 구원을 증거하는 것입니다.\n\n특별히 주목할 것은 12-13절의 확신입니다. 다윗은 현재의 어려움에도 불구하고 "여호와는 고난 당하는 자를 변호해 주시며 궁핍한 자에게 정의를 베푸시리이다"라고 선언합니다. 이것은 미래형으로 표현되었지만 흔들리지 않는 확신을 담고 있습니다. 의인들이 하나님의 이름에 감사하며 정직한 자들이 주의 앞에서 살 것이라는 마지막 고백은, 악인들의 일시적 번영에 흔들리지 않는 영원한 관점을 보여줍니다.\n\n오늘 우리도 다양한 형태의 ''악인들''을 만납니다. 부당한 비난을 퍼붓는 사람들, 교묘한 계략으로 해치려는 이들, 권력을 남용하여 약자를 괴롭히는 자들이 있을 수 있습니다. 그때 우리는 자신의 힘으로 맞서거나 동일한 방법으로 보복하려는 유혹을 받습니다. 그러나 다윗은 오직 하나님께 자신의 사정을 아뢰고, 정의로우신 재판장이신 하나님께 모든 것을 맡깁니다. 이것이 진정한 믿음의 능력입니다. 악의 현실을 부정하지 않으면서도, 궁극적인 정의와 구원이 하나님께 있음을 신뢰하는 것입니다.', E'오늘의 핵심\n악인의 위협이 실재할지라도, 고난 당하는 자를 변호하시고 정의를 베푸시는 하나님께 우리의 모든 사정을 맡길 때 참된 평안과 승리를 경험하게 됩니다.\n\n묵상 질문\n1. 내 삶에서 ''뱀의 혀''같은 악의적인 말들로 인해 상처받은 경험이 있나요? 그때 어떻게 대응했나요?\n2. "주는 나의 하나님"이라는 다윗의 고백이 내게는 얼마나 실제적인가요?\n3. 악이 득세하는 것처럼 보일 때도 하나님의 정의를 신뢰할 수 있는 근거는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-25', E'오므리 왕조 (열왕기상 16장)', E'열왕기상 16장', E'북이스라엘의 역사는 끊임없는 반역과 쿠데타의 연속이었습니다. 바아사가 여로보암의 집을 멸하고 왕이 되었지만, 그 역시 여로보암의 길을 따라 걸으며 백성들을 죄로 이끌었습니다. 하나님께서는 선지자 예후를 통해 바아사와 그의 집에 대한 심판을 선포하셨고, 그 말씀대로 바아사의 아들 엘라가 왕이 된 지 2년 만에 시므리의 반역으로 죽임을 당합니다. 시므리는 바아사의 온 집안을 멸절시켰는데, 이는 예후 선지자를 통해 선포된 하나님의 말씀이 그대로 성취된 것이었습니다.\n\n그러나 시므리의 통치는 겨우 7일 만에 끝나고 맙니다. 군대 지휘관 오므리가 반란을 일으켰고, 시므리는 왕궁에 불을 지르고 그 속에서 스스로 목숨을 끊었습니다. 오므리가 디브니와의 권력 다툼 끝에 왕위에 오른 후, 그는 사마리아 산을 사서 새로운 수도를 건설합니다. 정치적으로는 성공한 왕이었지만, 영적으로는 "그 전의 모든 사람보다 더욱 악하게" 행한 왕이었습니다.\n\n오므리의 뒤를 이은 아합은 시돈 왕 엣바알의 딸 이세벨과 결혼하면서 북이스라엘에 바알 숭배를 본격적으로 들여옵니다. 사마리아에 바알 신전을 짓고 제단을 쌓으며 아세라 상을 세웠습니다. 성경은 아합이 "그 이전의 이스라엘의 모든 왕보다 심히 이스라엘 하나님 여호와를 노하시게 하였더라"고 기록합니다. 북이스라엘의 영적 타락이 절정에 이른 것입니다. 이 시대에 여리고 성을 재건하려던 히엘이 여호수아의 저주대로 자녀들을 잃은 사건은, 하나님의 말씀이 여전히 살아 역사하심을 보여줍니다.', E'오늘의 핵심\n북이스라엘의 왕들이 계속해서 여로보암의 죄악된 길을 따르며 더욱 악해져 가는 가운데, 아합 시대에 이르러 바알 숭배가 국가적으로 공인되는 영적 암흑기가 시작됩니다.\n\n묵상 질문\n1. 반복되는 죄의 역사 속에서도 하나님의 말씀은 어떻게 성취되고 있나요?\n2. 정치적 성공과 영적 실패의 대조가 내 삶에 주는 교훈은 무엇인가요?\n3. 악이 점점 더해가는 시대에 신앙인으로서 어떻게 살아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-26', E'오므리 왕조 (열왕기상 17장)', E'열왕기상 17장', E'북이스라엘이 바알 숭배로 물들어 가던 그때, 길르앗의 디셉 출신 엘리야가 아합 왕 앞에 나타납니다. 그는 단호하게 선언합니다. "내 말이 없으면 수 년 동안 비도 이슬도 있지 아니하리라"(왕상 17:1). 풍요와 다산의 신이라 여겨지던 바알의 무력함을 드러내시려는 하나님의 계획이었습니다. \n\n하나님께서는 엘리야를 그릿 시냇가로 인도하셨고, 그곳에서 까마귀들이 아침저녁으로 떡과 고기를 날라다 주었습니다. 부정한 짐승으로 여겨지던 까마귀가 하나님의 종을 먹이는 도구가 되었다는 것은 놀라운 역설입니다. 시내가 마른 후에는 시돈 땅 사르밧의 한 과부에게로 가라고 하셨습니다. 이세벨의 고향인 시돈, 바알 숭배의 중심지로 엘리야를 보내신 것입니다.\n\n사르밧 과부는 마지막 남은 가루와 기름으로 아들과 함께 최후의 식사를 준비하려던 참이었습니다. 엘리야는 그녀에게 먼저 자신을 위해 작은 떡을 만들어 달라고 요청합니다. 인간적으로는 무리한 요구였지만, 과부는 순종했고 그 결과 통의 가루와 병의 기름이 떨어지지 않는 기적을 경험했습니다. 하나님께서는 이방 땅의 과부를 통해서도 당신의 종을 돌보실 수 있음을 보여주셨습니다.\n\n더 놀라운 일이 이어집니다. 과부의 아들이 숨을 거두자 엘리야는 그 아이를 안고 다락으로 올라가 간절히 기도했습니다. 세 번이나 아이 위에 몸을 펴서 엎드리며 부르짖었을 때, 하나님께서는 그 아이의 생명을 되돌려 주셨습니다. 이를 본 과부는 "당신의 입에 있는 여호와의 말씀이 진실한 줄 아노라"고 고백합니다. \n\n가뭄의 심판 가운데서도 하나님께서는 당신의 종을 보호하시고, 믿음으로 순종하는 이방인까지도 축복하셨습니다. 바알이 줄 수 없는 생명과 공급의 능력을 참 하나님만이 주실 수 있음을 분명히 보여주신 것입니다.', E'오늘의 핵심\n하나님께서는 바알 숭배에 빠진 이스라엘을 가뭄으로 심판하시면서도, 엘리야와 순종하는 이방인 과부를 기적적으로 돌보시며 당신만이 참 신이심을 증명하십니다.\n\n묵상 질문\n1. 하나님께서 까마귀와 이방인 과부를 통해 엘리야를 돌보신 것이 우리에게 주는 교훈은 무엇일까요?\n2. 사르밧 과부처럼 마지막 남은 것까지 하나님께 드릴 수 있는 믿음이 내게 있나요?\n3. 오늘날 우리가 의지하는 ''바알''은 무엇이며, 참된 생명의 근원은 어디에 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-28', E'예후의 치적과 엘리사 (열왕기하 9장)', E'열왕기하 9장', E'열왕기하 9장은 하나님의 심판이 마침내 아합 왕가에 임하는 역사적 순간을 보여줍니다. 엘리사는 한 젊은 선지자를 길르앗 라못으로 보내어 예후에게 기름을 부어 왕으로 세우게 합니다. 이는 엘리야가 호렙산에서 받았던 사명의 완성이었습니다.\n\n예후가 기름 부음을 받자 동료 장군들은 즉시 그를 왕으로 추대합니다. 그들은 각자의 겉옷을 벗어 예후의 발 아래 깔고 나팔을 불며 "예후는 왕이라"고 외쳤습니다. 이는 단순한 군사 쿠데타가 아니라 하나님의 뜻을 따르는 거룩한 심판의 시작이었습니다.\n\n예후는 이스르엘로 달려가 요람 왕을 만납니다. 그 만남의 장소가 나봇의 포도원이었다는 것은 의미심장합니다. 바로 그곳에서 아합과 이세벨이 무고한 나봇을 죽이고 그의 땅을 빼앗았기 때문입니다. "네 어머니 이세벨의 음행과 술수가 이렇게 많으니 어찌 평안이 있으랴"(왕하 9:22)라는 예후의 선언은 아합 왕가의 우상숭배와 불의가 얼마나 깊었는지를 보여줍니다.\n\n요람은 나봇의 포도원에서 죽임을 당하고, 아하시야도 도주하다 죽습니다. 이세벨 역시 창밖으로 던져져 죽임을 당하는데, 그녀의 시체는 개들이 먹어 두골과 손발만 남게 됩니다. 이 모든 일은 엘리야를 통해 선포된 하나님의 말씀대로 정확히 이루어졌습니다.\n\n하나님의 공의는 때로 더디게 실현되는 것처럼 보입니다. 나봇이 억울하게 죽은 후에도 아합 왕가는 여전히 왕위를 지켰고, 이세벨은 여전히 권력을 휘둘렀습니다. 그러나 하나님은 잊지 않으셨습니다. 정한 때가 되자 하나님은 예후라는 도구를 통해 악을 심판하셨습니다. \n\n이 본문은 우리에게 하나님의 공의가 반드시 실현된다는 것을 가르쳐 줍니다. 동시에 권력과 탐욕에 눈이 멀어 하나님을 거역하는 일이 얼마나 무서운 결과를 가져오는지도 보여줍니다. 오늘 우리는 나봇처럼 억울함을 당할 수도 있고, 때로는 악이 승리하는 것처럼 보일 수도 있습니다. 그러나 하나님은 모든 것을 보고 계시며, 그분의 때에 반드시 공의를 이루실 것입니다.', E'오늘의 핵심\n하나님께서는 예후를 통해 아합 왕가를 심판하시면서, 나봇의 억울한 죽음에 대한 공의를 실현하십니다. 하나님의 말씀은 반드시 성취됩니다.\n\n묵상 질문\n1. 악이 번성하는 것처럼 보일 때, 하나님의 공의를 어떻게 신뢰할 수 있을까요?\n2. 나봇의 포도원에서 요람이 죽은 것은 우리에게 무엇을 가르쳐 줍니까?\n3. 권력과 탐욕의 유혹 앞에서 나는 어떻게 하나님을 선택할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-29', E'예후의 치적과 엘리사 (열왕기하 10장)', E'열왕기하 10장', E'예후의 개혁은 철저함과 잔인함 사이에서 아슬아슬하게 줄타기를 합니다. 하나님께서 엘리야를 통해 예언하신 대로 아합 가문의 심판이 실행되는 장면은 정의의 실현인 동시에 인간의 야심이 뒤섞인 복잡한 역사의 한 페이지입니다.\n\n예후는 먼저 사마리아의 지도자들에게 편지를 보내 아합의 아들 70명 중에서 왕을 세우라고 도발합니다. 그러나 이미 두 왕을 죽인 예후의 기세에 눌린 그들은 항복을 선택하고, 결국 왕자들을 모두 죽여 그 머리를 예후에게 보냅니다. 예후는 이를 두고 "여호와께서 아합의 집에 대하여 하신 말씀은 하나도 땅에 떨어지지 아니하리라"고 선언합니다. 하나님의 심판이 성취되었다는 것입니다.\n\n그러나 예후의 행보는 여기서 멈추지 않습니다. 그는 바알 숭배자들을 모조리 제거하기 위해 거짓 계략을 꾸밉니다. 자신이 바알을 더욱 열심히 섬기겠다고 선언하여 바알의 모든 제사장과 예배자들을 한 곳에 모은 뒤, 그들을 몰살시킵니다. 바알의 신전은 파괴되고 그 자리는 화장실이 됩니다. 이스라엘에서 바알 숭배가 완전히 근절되는 순간이었습니다.\n\n하나님께서는 예후의 이러한 행동을 인정하셨습니다. "네가 나보기에 정직한 일을 행하되 잘 행하여 내 마음에 있는 대로 아합 집에 다 행하였은즉"이라고 말씀하시며, 그의 자손이 4대까지 왕위에 오를 것을 약속하십니다. 그러나 성경은 예후의 한계도 분명히 지적합니다. 그는 "전심으로 이스라엘 하나님 여호와의 율법을 지켜 행하지 아니하며" 여로보암이 세운 금송아지는 그대로 두었습니다.\n\n예후의 개혁은 우리에게 중요한 질문을 던집니다. 악을 제거하는 열심은 있었지만, 하나님을 온전히 따르는 마음은 부족했습니다. 바알은 없앴지만 금송아지는 남겨둔 그의 모습은, 우리가 신앙생활에서 보이는 선택적 순종의 모습과 닮아 있습니다. 진정한 개혁은 눈에 보이는 우상만 제거하는 것이 아니라, 마음 깊은 곳의 우상까지 내려놓는 것임을 열왕기는 조용히 가르쳐줍니다.', E'오늘의 핵심\n예후는 하나님의 심판을 수행하여 아합 가문과 바알 숭배를 제거했지만, 전심으로 하나님을 따르지는 못했습니다. 부분적 순종이 아닌 온전한 헌신이 필요합니다.\n\n묵상 질문\n1. 내 삶에서 제거해야 할 ''바알''은 무엇이며, 아직 남겨둔 ''금송아지''는 무엇인가요?\n2. 하나님의 뜻을 행한다는 명분으로 인간적 야심을 정당화한 적은 없나요?\n3. 선택적 순종이 아닌 전심으로 하나님을 따른다는 것은 무엇을 의미할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-01', E'정의를 강물 같이 (아모스 6장)', E'아모스 6장', E'아모스는 북이스라엘의 지도자들을 향해 날카로운 심판의 메시지를 전합니다. "화 있을진저 시온에서 교만한 자와 사마리아 산에서 마음이 든든한 자"라는 선포로 시작되는 이 예언은, 안일과 사치에 빠진 지도층의 실상을 적나라하게 드러냅니다. 그들은 상아 침대에 누워 어린 양과 송아지를 잡아먹으며, 대접으로 포도주를 마시고 귀한 기름을 몸에 바르는 호화로운 삶을 누리고 있었습니다. 다윗처럼 악기를 만들어 연주하며 향락에 빠져 있었지만, 정작 "요셉의 환난"으로 표현되는 백성들의 고통에는 전혀 관심이 없었습니다.\n\n하나님께서는 이들의 거짓된 안전감을 지적하십니다. 그들은 갈레, 하맛, 가드 같은 주변 강국들과 자신들을 비교하며 우월감에 취해 있었고, "흉한 날이 멀다"고 여기며 심판을 외면했습니다. 그러나 아모스는 이러한 교만이 오히려 "포악한 자리로 가까워지게" 만든다고 경고합니다. 정의를 쓸개로, 공의의 열매를 쓴 쑥으로 바꾸어버린 그들의 타락상은 하나님의 진노를 불러일으켰습니다.\n\n특히 12절의 수사적 질문은 깊은 울림을 줍니다. "말들이 어찌 바위 위에서 달리겠으며 소가 어찌 거기서 밭 갈겠느냐" - 이는 북이스라엘이 얼마나 상식과 질서를 거스르는 삶을 살고 있는지를 보여주는 비유입니다. 정의와 공의라는 사회의 기본 토대를 무너뜨린 그들에게 하나님은 철저한 심판을 선언하십니다. 사로잡힘이 임할 것이며, 한 집에 열 사람이 있어도 모두 죽을 것이라는 무서운 예언이 주어집니다.\n\n이 말씀은 오늘날 우리에게도 엄중한 경고가 됩니다. 물질적 풍요와 안락함 속에서 이웃의 고통을 외면하고, 정의와 공의를 저버린 채 살아가는 것은 하나님께서 가장 미워하시는 일임을 아모스는 분명히 전해주고 있습니다.', E'오늘의 핵심\n하나님께서는 사치와 향락에 빠져 백성의 고통을 외면하는 북이스라엘 지도층의 불의를 심판하시며, 정의와 공의를 상실한 사회의 필연적 멸망을 선언하십니다.\n\n묵상 질문\n1. 나는 혹시 물질적 안락함 속에서 주변의 아픔과 불의를 못 본 척하고 있지는 않나요?\n2. 하나님께서 우리 사회에 요구하시는 정의와 공의를 위해 내가 할 수 있는 일은 무엇일까요?\n3. "요셉의 환난"에 무관심한 지도자들의 모습이 오늘날 우리에게 주는 교훈은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-02', E'정의를 강물 같이 (아모스 7장)', E'아모스 7장', E'아모스 7장은 하나님께서 북이스라엘에 내리실 심판을 세 가지 환상으로 보여주시는 것으로 시작됩니다. 첫 번째 환상에서 하나님은 왕이 풀을 벤 후 새로 돋아나는 풀을 메뚜기가 먹어치우는 재앙을 준비하십니다. 이는 백성들의 마지막 희망마저 사라지게 하는 철저한 심판이었습니다. 두 번째 환상에서는 큰 바다를 삼키고 육지까지 태우려는 불의 심판이 준비됩니다. 이 두 환상에서 아모스는 "야곱이 미약하오니 어떻게 서리이까"라며 간절히 중보기도를 드렸고, 하나님께서는 그의 기도를 들으시고 뜻을 돌이키셨습니다. 여기서 우리는 심판을 선포하시는 하나님의 마음에도 여전히 긍휼이 있음을 발견하게 됩니다.\n\n그러나 세 번째 환상은 달랐습니다. 하나님께서 다림줄을 들고 서신 모습은 더 이상 용서가 없는 최종 심판을 의미했습니다. 다림줄은 건축물의 수직을 측정하는 도구로, 하나님께서 이스라엘의 영적 상태를 정확히 측량하시겠다는 선언이었습니다. "다시는 용서하지 아니하리니"라는 하나님의 선언은 북이스라엘을 향한 마지막 심판이 확정되었음을 보여줍니다.\n\n이러한 심판의 메시지는 벧엘 제사장 아마샤의 격렬한 반발을 불러일으켰습니다. 그는 아모스를 여로보암 왕에게 모반자로 고발하고, 남쪽 유다로 돌아가라고 협박했습니다. 그러나 아모스의 대답은 담대했습니다. 자신은 직업적 선지자가 아니라 목자요 뽕나무 재배자였으나, 하나님께서 양 떼를 따르던 자신을 불러 이스라엘에게 예언하라 명하셨다는 것입니다. 이는 하나님의 부르심이 인간의 신분이나 직업을 초월한다는 것을 보여줍니다. 아모스는 오히려 아마샤와 그의 가족에게 임할 비참한 운명을 선포함으로써, 하나님의 말씀을 거부하는 자들의 결말을 분명히 했습니다.', E'오늘의 핵심\n하나님께서는 끝까지 회개하지 않는 북이스라엘에 최종 심판을 선언하시며, 평범한 목자 아모스를 통해 그 누구도 하나님의 부르심과 심판을 막을 수 없음을 보여주십니다.\n\n묵상 질문\n1. 아모스의 중보기도에 응답하시는 하나님의 마음을 통해 무엇을 느끼시나요?\n2. 하나님의 다림줄 앞에 나의 삶은 얼마나 바르게 서 있습니까?\n3. 평범한 직업인이었던 아모스의 소명이 오늘 나에게 주는 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-03', E'정의를 강물 같이 (아모스 8장)', E'아모스 8장', E'여름 과일 한 광주리의 환상은 북이스라엘의 운명을 극적으로 보여줍니다. 히브리어로 ''여름 과일''(카이츠)과 ''끝''(케츠)이 비슷한 발음을 가진 것을 통해, 하나님께서는 이스라엘의 완숙한 심판의 때가 이르렀음을 선언하십니다. 더 이상 용서하지 않으시겠다는 단호한 말씀은 그동안 수없이 기회를 주셨던 하나님의 인내가 끝났음을 의미합니다.\n\n아모스가 고발하는 당시 상인들의 모습은 충격적입니다. 그들은 안식일과 월삭이 빨리 끝나기만을 기다리며, 에바(곡물 단위)는 작게 하고 세겔(화폐 단위)은 크게 하여 거짓 저울로 속입니다. 심지어 가난한 자를 신 한 켤레 값으로 사고파는 인신매매까지 서슴지 않으며, 찌꺼기 밀을 섞어 팔기도 합니다. 하나님께서 주신 안식일이 그들에게는 장사를 방해하는 걸림돌일 뿐이었습니다.\n\n이러한 불의에 대한 하나님의 심판은 철저합니다. 대낮에 해가 지는 우주적 재앙, 모든 절기와 노래가 애곡으로 변하는 비극, 그리고 무엇보다 가장 무서운 심판은 "여호와의 말씀을 듣지 못한 기갈"입니다. 사람들이 이 바다에서 저 바다까지, 북쪽에서 동쪽까지 하나님의 말씀을 구하려 헤매도 찾을 수 없게 됩니다. 물질적 풍요 속에서 영적 기근을 맞는 것, 이것이 말씀을 거부한 이들에게 임할 가장 비참한 운명입니다.\n\n사마리아의 우상과 브엘세바의 신들을 의지하던 자들의 최후가 선포됩니다. 그들은 엎드러져 다시는 일어나지 못할 것입니다. 하나님의 공의는 물같이 흘러야 하는데, 그들은 그 물길을 막고 자신들의 탐욕으로 채웠습니다. 이제 그 댓가를 치러야 할 때가 왔습니다.', E'오늘의 핵심\n하나님께서는 가난한 자를 착취하고 안식일마저 장사의 걸림돌로 여기는 이스라엘에게 가장 무서운 심판인 ''말씀의 기근''을 선포하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 중요하게 여기며 기다리는 것은 무엇인가요?\n2. 주변의 약자들을 대하는 나의 태도는 하나님의 공의를 반영하고 있나요?\n3. 하나님의 말씀이 내 삶에서 진정한 양식이 되고 있는지 점검해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-04', E'정의를 강물 같이 (아모스 9장)', E'아모스 9장', E'아모스가 본 다섯 번째 환상은 무너지는 벧엘 성전의 모습으로 시작됩니다. 하나님께서 제단 곁에 서서 기둥을 치라고 명하시는 장면은 북이스라엘의 우상숭배 중심지였던 벧엘이 완전히 파괴될 것을 보여줍니다. 이 심판은 너무나 철저하여 "한 사람도 도망하지 못하며 한 사람도 피하지 못하리라"(암 9:1)는 선언이 이어집니다. 스올이든 하늘이든, 갈멜 산 꼭대기든 바다 밑이든 어디에도 피할 곳이 없다는 표현은 하나님의 심판이 얼마나 완전할 것인지를 보여줍니다.\n\n특별히 하나님께서는 이스라엘이 다른 민족들과 다르지 않다고 선언하십니다. 구스 족속처럼 여기신다는 말씀은 선민이라는 특권에 안주하며 불의를 행해온 이스라엘에 대한 준엄한 경고입니다. 하나님께서는 블레셋과 아람도 인도하셨듯이 모든 민족의 역사를 주관하시는 분이십니다. 그러므로 이스라엘의 선택받음은 특권이 아니라 더 큰 책임을 의미하는 것이었습니다.\n\n그러나 놀랍게도 이 철저한 심판의 선언 가운데서도 하나님의 자비는 빛을 발합니다. "야곱의 집은 온전히 멸하지는 아니하리라"는 약속과 함께, 체로 체질하듯 흩어진 백성 중에서 한 알갱이도 땅에 떨어지지 않게 하시겠다는 은혜의 말씀이 이어집니다. 더 나아가 무너진 다윗의 장막을 다시 세우시고, 황폐한 땅이 회복되어 파종하는 자가 추수하는 자를 따라잡을 정도로 풍성한 축복이 임할 것을 약속하십니다. 이는 단순한 물질적 회복을 넘어 하나님과의 관계가 온전히 회복될 메시아 시대의 소망을 담고 있습니다.', E'오늘의 핵심\n하나님께서는 북이스라엘에 대한 철저한 심판을 선언하시면서도, 남은 자를 통한 회복의 약속으로 끝없는 사랑과 신실하심을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판을 피할 곳이 없다는 말씀이 주는 두려움과 동시에 위로는 무엇인가요?\n2. 선민 의식에 안주하며 책임을 망각한 이스라엘의 모습에서 오늘날 교회가 배워야 할 교훈은 무엇일까요?\n3. 체로 거르시되 한 알갱이도 떨어뜨리지 않으시는 하나님의 세심한 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-06', E'호세아의 결혼과 하나님의 사랑 (호세아 1장)', E'호세아 1장', E'호세아서는 하나님께서 선지자에게 매우 특별하고도 충격적인 명령을 내리시는 것으로 시작됩니다. "너는 가서 음란한 여자를 맞이하여 음란한 자식들을 낳으라"(호 1:2)는 말씀이었습니다. 이 명령은 단순히 한 개인의 결혼 이야기가 아니라, 북이스라엘을 향한 하나님의 아픈 마음을 보여주는 살아있는 비유였습니다.\n\n호세아가 맞이한 고멜은 바알 숭배와 연관된 음란한 여인이었습니다. 그녀와의 결혼은 호세아에게 평생의 고통과 수치를 안겨주었을 것입니다. 그런데 하나님께서는 바로 이 고통스러운 결혼을 통해 당신의 백성을 향한 마음을 드러내고자 하셨습니다. 이스라엘이 하나님과의 언약을 배반하고 우상을 섬기는 모습이 곧 고멜의 음란함과 같았기 때문입니다.\n\n고멜이 낳은 세 자녀의 이름은 각각 하나님의 심판을 예고합니다. 첫째 아들 ''이스르엘''은 예후가 이스르엘에서 벌인 유혈 사태를 상기시키며, 북이스라엘의 멸망을 예고합니다. 둘째 딸 ''로루하마''(긍휼히 여김을 받지 못함)와 셋째 아들 ''로암미''(내 백성이 아님)의 이름은 하나님께서 언약 백성과의 관계를 끊으시겠다는 선언이었습니다.\n\n그러나 놀랍게도 1장의 마지막은 회복의 약속으로 끝납니다. 하나님께서는 심판 선언 직후에 "이스라엘 자손의 수가 바닷가의 모래 같이 되어서 헤아릴 수도 없고 셀 수도 없을 것"이라고 말씀하십니다. ''내 백성이 아니라'' 했던 그곳에서 ''살아 계신 하나님의 아들들''이라 불릴 것이라는 약속입니다. 이것은 아브라함에게 주신 언약을 상기시키며, 심판 너머에 있는 구원의 소망을 보여줍니다.\n\n호세아의 아픈 결혼 생활은 우상 숭배로 더럽혀진 이스라엘을 여전히 사랑하시는 하나님의 마음을 보여주는 거울이었습니다. 배신당하고 상처받으면서도 끝까지 사랑하시는 하나님, 심판 중에도 회복을 약속하시는 그 신실하심이 호세아서 첫 장에 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 호세아와 음란한 여인 고멜의 결혼을 통해 우상 숭배에 빠진 이스라엘을 향한 당신의 아픈 사랑과 심판, 그리고 회복의 약속을 보여주십니다.\n\n묵상 질문\n1. 호세아가 고멜과의 결혼으로 겪은 고통을 통해 하나님의 어떤 마음을 이해할 수 있을까요?\n2. 내 삶에서 하나님보다 더 의지하고 있는 ''우상''은 무엇인가요?\n3. 심판 중에도 회복을 약속하시는 하나님의 신실하심이 오늘 나에게 어떤 위로가 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-07', E'호세아의 결혼과 하나님의 사랑 (호세아 2장)', E'호세아 2장', E'호세아 2장은 하나님과 이스라엘의 관계를 부부관계로 표현하면서 더욱 극적인 전환을 보여줍니다. 하나님께서는 음행하는 아내 같은 이스라엘을 향해 먼저 심판을 선언하십니다. 그들이 바알에게서 받았다고 착각하는 곡식과 포도주와 기름이 사실은 하나님께서 주신 것임을 깨닫지 못하는 어리석음을 지적하십니다. 이스라엘은 하나님의 은혜를 망각하고 그 선물을 가지고 오히려 우상을 섬기는 데 사용했습니다.\n\n하나님의 심판은 단순한 징벌이 아니라 회복을 위한 과정입니다. 가시로 길을 막고 담을 쌓아 이스라엘이 우상을 따라가지 못하게 하시는 것은, 그들이 돌이켜 본래의 남편인 하나님께로 돌아오게 하려는 사랑의 표현입니다. "내가 본 남편에게로 돌아가리니 그 때의 내 형편이 지금보다 나았음이라"(2:7)라는 깨달음에 이르도록 인도하시는 것입니다.\n\n그런데 14절부터는 놀라운 반전이 일어납니다. 심판의 메시지가 갑자기 사랑의 언어로 바뀝니다. 하나님께서 이스라엘을 광야로 데리고 가서 말로 위로하시겠다고 하십니다. 광야는 이스라엘이 하나님과 처음 사랑을 나누던 장소였습니다. 출애굽 직후 아무것도 없는 광야에서 오직 하나님만 의지하며 살았던 그 시절로 돌아가 새롭게 시작하자는 것입니다. 아골 골짜기, 곧 아간의 범죄로 절망했던 그곳을 소망의 문으로 바꾸시겠다는 약속은 하나님의 은혜가 얼마나 크신지를 보여줍니다.\n\n무엇보다 감동적인 것은 19-20절의 약속입니다. 하나님께서 이스라엘에게 다시 장가들겠다고 하시면서, 그것도 "공의와 정의와 은총과 긍휼히 여김으로" 장가들겠다고 하십니다. 배신당한 남편이 돌아온 아내를 그저 받아주는 것이 아니라, 처음보다 더 깊은 사랑으로 새로운 언약을 맺으시는 것입니다. 이것이 우리를 향한 하나님의 마음입니다.', E'오늘의 핵심\n하나님께서는 우상을 섬기며 배신한 이스라엘을 심판하시지만, 그 심판마저도 회복을 위한 사랑의 과정이며, 결국 더 깊은 언약으로 그들과 다시 하나 되기를 원하십니다.\n\n묵상 질문\n1. 내가 하나님께 받은 은혜를 잊고 다른 것에 공로를 돌렸던 적은 없나요?\n2. 하나님께서 내 인생에 가시와 담을 두신 것처럼 느껴질 때, 그것이 사랑의 표현일 수 있을까요?\n3. "공의와 정의와 은총과 긍휼"로 나와 새 언약을 맺기 원하시는 하나님께 어떻게 응답하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-08', E'호세아의 결혼과 하나님의 사랑 (호세아 3장)', E'호세아 3장', E'호세아 3장은 하나님의 놀라운 사랑의 깊이를 보여주는 충격적인 장면으로 시작됩니다. 하나님께서는 호세아에게 또다시 명령하십니다. "타인의 사랑을 받아 음녀가 된 그 여자를 사랑하라"(호 3:1). 고멜은 호세아를 떠나 다른 남자와 살고 있었습니다. 아마도 노예로 팔려 있었을지도 모릅니다. 그런 아내를 다시 찾아가 사랑하라는 것입니다.\n\n호세아는 은 열다섯 개와 보리 한 호멜 반을 주고 아내를 되찾아옵니다. 이것은 당시 노예 한 명의 몸값에 해당하는 금액이었습니다. 배신한 아내를 위해 대가를 치르는 호세아의 모습은 죄인된 우리를 위해 독생자를 아끼지 않으신 하나님의 사랑을 떠올리게 합니다.\n\n호세아는 되찾은 아내에게 조건을 제시합니다. "너는 많은 날 동안 나와 함께 지내고 음행하지 말며 다른 남자를 따르지 말라." 이것은 단순한 요구가 아니라 관계 회복을 위한 정화의 시간이었습니다. 마찬가지로 이스라엘도 왕과 지도자, 제사와 우상 없이 지내는 시간을 거쳐야 했습니다. 이 고난의 시간은 심판이면서 동시에 회복을 위한 준비였습니다.\n\n호세아서는 이스라엘의 미래에 대한 소망으로 마무리됩니다. "그 후에 이스라엘 자손이 돌아와서 그들의 하나님 여호와와 그들의 왕 다윗을 찾고." 하나님께서는 배신한 백성을 끝까지 포기하지 않으십니다. 오히려 그들이 돌아올 날을 기다리며 회복의 길을 예비하고 계십니다.\n\n우리 삶에도 하나님을 떠났던 시간들이 있습니다. 세상의 가치와 욕망을 좇아 영적인 음행을 저질렀던 순간들이 있습니다. 그러나 하나님은 우리를 찾아오십니다. 값을 치르고 우리를 되찾으시며, 관계를 회복하기 원하십니다. 오늘도 그 사랑의 손길이 우리를 향해 뻗어 있습니다.', E'오늘의 핵심\n하나님께서는 배신한 백성을 포기하지 않으시고 값을 치러 되찾으시며, 정화의 시간을 통해 관계를 회복하고자 하십니다.\n\n묵상 질문\n1. 호세아가 배신한 아내를 위해 값을 치른 것처럼, 하나님이 나를 위해 치르신 대가는 무엇인가요?\n2. 내 삶에 필요한 ''정화의 시간''은 무엇이며, 하나님은 그 시간을 통해 무엇을 회복시키려 하실까요?\n3. "마지막 날에는 여호와를 경외하므로 나아가리라"는 소망이 내 삶에 어떤 위로와 힘을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-09', E'열방을 향한 사랑 (요나 1장)', E'요나 1장', E'하나님의 말씀이 요나에게 임했습니다. "너는 일어나 저 큰 성읍 니느웨로 가서 그것을 향하여 외치라"(욘 1:2). 니느웨는 당시 앗수르 제국의 수도로, 이스라엘을 위협하던 가장 잔인한 도시였습니다. 그런데 요나는 정반대 방향인 다시스로 향하는 배에 몸을 실었습니다. 단순한 두려움 때문이 아니었습니다. 그는 하나님의 성품을 너무나 잘 알고 있었기에, 혹시라도 니느웨가 회개하여 구원받는 것을 원치 않았던 것입니다.\n\n하나님께서는 큰 바람을 일으켜 요나가 탄 배를 흔드셨습니다. 이방인 선원들은 각자의 신에게 부르짖으며 짐을 바다에 던져 배를 가볍게 하려 애썼지만, 정작 이 모든 일의 원인인 요나는 배 밑층에서 깊이 잠들어 있었습니다. 제비뽑기를 통해 재앙의 원인이 밝혀지자, 요나는 자신이 "바다와 육지를 지으신 하늘의 하나님 여호와를 경외하는 자"임을 고백합니다. 그러면서도 여호와의 얼굴을 피하여 도망치는 모순된 행동을 했다고 시인합니다.\n\n흥미로운 것은 이방인 선원들의 반응입니다. 그들은 요나를 바다에 던지기를 주저하며 힘써 노를 저어 육지로 돌아가려 했습니다. 하나님을 모르던 이들이 오히려 한 생명을 아끼는 마음을 보여준 것입니다. 결국 요나를 바다에 던진 후 바다가 잔잔해지자, 그들은 여호와를 크게 두려워하며 제물을 드리고 서원을 했습니다. 도망치던 선지자가 의도치 않게 이방인들에게 하나님을 증거하는 도구가 된 것입니다.\n\n하나님께서는 큰 물고기를 예비하셔서 요나를 삼키게 하셨습니다. 이는 심판이 아닌 구원의 손길이었습니다. 우리가 아무리 하나님의 뜻을 거부하고 도망쳐도, 하나님의 주권적인 사랑은 우리를 포기하지 않으십니다. 때로는 폭풍을 통해, 때로는 물고기 뱃속 같은 절망적 상황을 통해 우리를 다시 그분의 뜻 안으로 인도하십니다.', E'오늘의 핵심\n하나님의 부르심을 거부하고 도망친 요나를 통해서도 하나님은 이방인들에게 자신을 계시하시며, 폭풍과 물고기를 통해 요나를 포기하지 않으시는 주권적 사랑을 보여주십니다.\n\n묵상 질문\n1. 내가 하나님의 뜻임을 알면서도 피하고 있는 일은 무엇인가요?\n2. 요나를 구하려 애쓴 이방 선원들의 모습에서 무엇을 배울 수 있을까요?\n3. 내 삶의 폭풍 속에서도 나를 포기하지 않으시는 하나님의 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-10', E'열방을 향한 사랑 (요나 2장)', E'요나 2장', E'물고기 뱃속은 요나에게 무덤이 아니라 기도실이 되었습니다. 하나님의 명령을 거역하고 도망치던 선지자가 이제 깊은 바다 속, 거대한 물고기의 뱃속에서 하나님께 부르짖습니다. 이 기도는 단순한 구원의 호소가 아니라, 철저한 회개와 새로운 헌신의 고백입니다.\n\n요나의 기도는 "스올의 뱃속에서"(2절) 시작됩니다. 죽음의 문턱에서 그는 비로소 하나님께서 자신의 유일한 소망임을 깨닫습니다. 깊은 바다 속, 해초에 머리가 감긴 채 산의 뿌리까지 내려간 그 절망적인 순간에도 요나는 "다시 주의 성전을 바라보겠다"(4절)고 고백합니다. 이것은 단순히 예루살렘 성전으로 돌아가겠다는 의미를 넘어, 하나님과의 관계를 회복하겠다는 간절한 소망의 표현입니다.\n\n특별히 주목할 것은 요나가 이 극한의 상황을 하나님의 징계로 받아들인다는 점입니다. "주께서 나를 깊음 속 바다 가운데에 던지셨으므로"(3절)라는 고백에서 볼 수 있듯이, 그는 자신의 고난이 우연이 아니라 하나님의 주권적인 섭리 안에 있음을 인정합니다. 이러한 깨달음은 그를 진정한 회개로 이끌었고, "거짓되고 헛된 것을 숭상하는" 삶에서 돌이켜 "감사하는 목소리로" 하나님께 나아가게 합니다.\n\n요나는 마침내 "구원은 여호와께 속하였나이다"(9절)라고 선포합니다. 이것은 단지 물고기 뱃속에서의 구출만을 의미하지 않습니다. 니느웨 사람들의 구원도, 이스라엘의 구원도, 모든 구원이 오직 하나님께 속해 있다는 깊은 깨달음입니다. 자기 민족만을 위한 좁은 신앙에서 벗어나, 모든 민족을 향한 하나님의 구원 계획을 받아들이기 시작한 것입니다.\n\n하나님께서는 요나의 기도를 들으시고 물고기에게 명하여 그를 육지에 토하게 하셨습니다. 이는 단순한 육체적 구원이 아니라, 새로운 사명을 위한 재출발의 은혜였습니다. 때로 우리도 자신이 만든 물고기 뱃속 같은 곤경에 빠질 때가 있습니다. 그러나 그곳이 오히려 하나님을 더 깊이 만나는 은혜의 자리가 될 수 있음을 요나의 기도가 보여줍니다.', E'오늘의 핵심\n물고기 뱃속이라는 절망적 상황에서 요나는 진정한 회개의 기도를 드리며, 구원이 오직 여호와께 속했음을 깨닫고 새로운 순종의 삶으로 나아갑니다.\n\n묵상 질문\n1. 내 삶의 "물고기 뱃속" 같은 순간에 하나님께 어떻게 기도했나요?\n2. 요나처럼 고난을 통해 하나님의 주권을 인정하게 된 경험이 있나요?\n3. "구원은 여호와께 속하였나이다"라는 고백이 내 삶에서 어떤 의미인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-11', E'열방을 향한 사랑 (요나 3장)', E'요나 3장', E'여호와의 말씀이 두 번째로 요나에게 임했습니다. 물고기 뱃속에서 회개한 요나에게 하나님은 처음과 동일한 사명을 다시 주십니다. 이번에는 요나가 순종하여 니느웨로 향합니다. 니느웨는 사흘 동안 걸어야 할 만큼 거대한 도시였습니다. 당시 앗수르 제국의 수도로서 그 위용과 악명이 온 근동에 자자했던 곳입니다. \n\n요나는 겨우 하루 동안만 성읍을 다니며 "사십 일이 지나면 니느웨가 무너지리라"는 짧은 메시지를 외쳤습니다. 사흘 길의 도시에서 하루만 다녔다는 것은 요나가 여전히 마지못해 사명을 수행하고 있음을 보여줍니다. 그의 선포에는 회개의 촉구도, 구원의 소망도 없었습니다. 단지 심판의 선언뿐이었습니다.\n\n그런데 놀라운 일이 벌어졌습니다. 니느웨 사람들이 하나님을 믿고 금식을 선포한 것입니다. 신분의 높고 낮음을 막론하고 모두가 굵은 베 옷을 입었습니다. 왕까지도 보좌에서 내려와 왕복을 벗고 재 위에 앉았습니다. 더욱 놀라운 것은 왕이 내린 조서의 내용입니다. 사람뿐 아니라 짐승까지도 금식하며 굵은 베 옷을 입고, 무엇보다 "각기 악한 길과 손으로 행한 강포에서 떠날 것"을 명령했습니다. 이것은 단순한 종교적 의식이 아니라 삶의 진정한 변화를 추구하는 회개였습니다.\n\n"하나님이 뜻을 돌이키시고 그 진노를 그치사 우리가 멸망하지 않게 하시리라"는 왕의 고백은 이방인이 보여준 놀라운 믿음의 표현입니다. 그들은 확신할 수 없었지만 하나님의 자비에 자신들의 운명을 맡겼습니다. 그리고 하나님은 그들의 회개를 보시고 재앙을 거두셨습니다.\n\n이 장면은 우리에게 중요한 진리를 가르쳐줍니다. 구원의 역사는 전하는 사람의 열정이나 웅변에 달린 것이 아니라, 하나님의 말씀 자체가 지닌 능력과 듣는 사람의 마음을 여시는 하나님의 은혜에 달려 있다는 것입니다. 마지못해 전한 메시지조차 하나님은 사용하실 수 있으며, 가장 악명 높은 도시도 하나님 앞에서는 회개할 수 있습니다.', E'오늘의 핵심\n마지못해 전해진 심판의 메시지조차도 하나님은 니느웨의 구원을 위해 사용하셨고, 악명 높던 이방 도시가 진정한 회개로 하나님의 긍휼을 경험하게 하셨습니다.\n\n묵상 질문\n1. 요나의 성의 없는 선포에도 니느웨가 회개한 것을 보며 무엇을 깨닫게 되시나요?\n2. 니느웨 왕이 보여준 철저한 회개의 모습에서 나는 어떤 도전을 받나요?\n3. 하나님의 말씀이 내 삶과 주변에 능력으로 나타나기를 어떻게 기도하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-13', E'열방을 향한 사랑 (요나 4장)', E'요나 4장', E'니느웨가 회개하고 하나님께서 재앙을 거두신 것을 본 요나는 오히려 크게 분노합니다. 그의 기도는 놀라운 고백을 담고 있습니다. "주께서는 은혜로우시며 자비로우시며 노하기를 더디하시며 인애가 크시사 뜻을 돌이켜 재앙을 내리지 아니하시는 하나님이신 줄을 내가 알았음이니이다"(욘 4:2). 요나는 처음부터 하나님의 성품을 정확히 알고 있었습니다. 그가 다시스로 도망친 진짜 이유는 두려움이 아니라 니느웨가 구원받는 것을 원치 않았기 때문이었습니다.\n\n하나님은 분노하는 요나에게 박넝쿨의 비유를 통해 가르치십니다. 요나가 성읍 동쪽에서 니느웨의 운명을 지켜보고 있을 때, 하나님은 박넝쿨을 자라게 하셔서 그에게 그늘을 주셨습니다. 요나는 이 작은 은혜에 크게 기뻐했지만, 다음날 벌레가 그것을 갉아먹자 다시 죽기를 원할 만큼 괴로워합니다. 하나님은 이런 요나에게 물으십니다. 네가 수고하지도 않고 하룻밤에 났다가 사라진 박넝쿨도 아까워하면서, 어찌 좌우를 분변하지 못하는 십이만여 명과 많은 가축이 있는 니느웨를 내가 아끼지 않겠느냐고 말입니다.\n\n이 대조를 통해 하나님은 요나의 편협한 민족주의와 선택적 긍휼을 드러내십니다. 요나는 자신에게 유익한 작은 식물에는 애착을 가지면서도, 하나님이 창조하시고 사랑하시는 수많은 생명에는 무관심했습니다. 하나님의 긍휼은 이스라엘만을 위한 것이 아니라 모든 민족을 향한 것입니다. 그분은 심판하시는 하나님이시면서 동시에 회개하는 자를 기다리시는 자비의 하나님이십니다.\n\n요나서는 열린 결말로 끝납니다. 하나님의 질문에 요나가 어떻게 대답했는지 기록하지 않습니다. 이것은 오늘 우리에게도 던져진 질문입니다. 우리도 종종 하나님의 은혜가 ''그들''에게까지 미치는 것을 불편해하지 않습니까? 내가 정한 경계선 밖의 사람들, 용서받을 자격이 없다고 생각하는 이들에게도 하나님의 사랑은 동일하게 부어집니다. 하나님의 마음은 모든 영혼을 향해 열려 있습니다.', E'오늘의 핵심\n하나님은 박넝쿨의 비유를 통해 요나의 편협한 시각을 드러내시고, 모든 생명을 아끼시는 창조주 하나님의 넓은 사랑을 보여주십니다.\n\n묵상 질문\n1. 내가 하나님의 은혜를 ''자격 있는 사람''에게만 제한하고 있지는 않나요?\n2. 작은 개인적 유익에는 민감하면서 타인의 구원에는 무관심한 모습이 내게도 있지 않을까요?\n3. 하나님께서 아끼시는 사람을 내가 미워하거나 외면하고 있다면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-14', E'이사야의 소명 (이사야 1장)', E'이사야 1장', E'하나님께서는 당신의 백성을 향해 깊은 탄식을 쏟아내십니다. "소는 그 임자를 알고 나귀는 그 주인의 구유를 알건마는 이스라엘은 알지 못하고 나의 백성은 깨닫지 못하는도다"(사 1:3). 짐승도 자기를 먹이는 손을 기억하는데, 하나님의 사랑 안에서 자라온 백성은 그 하나님을 외면하고 있었습니다. 이사야를 통해 전해지는 하나님의 첫 메시지는 자녀를 잃은 아버지의 아픔이었습니다.\n\n남유다의 영적 상태는 참담했습니다. 발바닥에서 머리까지 성한 곳이 없고, 온 몸이 상처투성이인 것처럼 묘사됩니다. 앗수르의 침략으로 땅은 황폐해지고 성읍들은 불탔으며, 시온은 포도원의 망대처럼 외롭게 남겨졌습니다. 그런데 더 비극적인 것은, 그들이 여전히 제사를 드리고 절기를 지키고 있었다는 사실입니다. 성전에는 제물이 넘쳐났고, 월삭과 안식일마다 사람들이 모였습니다.\n\n하나님은 이 형식적인 예배를 향해 "헛된 제물을 다시 가져오지 말라"고 단호하게 말씀하십니다. 손을 들어 기도하지만 그 손에 피가 가득하고, 성회에 모이면서도 악을 행하는 모순된 삶을 하나님은 견디지 못하셨습니다. 고관들은 뇌물을 받고 불의를 행하며, 고아와 과부의 억울함은 외면당했습니다. 겉으로는 종교적이지만 안으로는 정의와 공의가 텅 비어 있는, 내용 없는 신앙이었습니다.\n\n그러나 하나님은 심판의 메시지 한가운데서 놀라운 초청을 하십니다. "오라 우리가 서로 변론하자 너희의 죄가 주홍 같을지라도 눈과 같이 희어질 것이요." 이것은 이사야서 전체를 관통하는 은혜의 선언입니다. 죄를 드러내시되 거기서 멈추지 않으시고, 회복의 길을 열어두시는 하나님의 마음입니다. 동시에 구체적인 삶의 변화를 요구하십니다. 선행을 배우고, 정의를 구하고, 학대받는 자를 돕고, 고아와 과부를 돌보라고 하십니다. 참된 예배는 삶의 현장에서 정의와 사랑으로 드러나는 것임을 분명히 하십니다.\n\n하나님께서는 시온을 정의로 구속하시고, 돌아온 자들을 공의로 회복시키겠다고 약속하십니다. 찌꺼기를 제거하고 정결케 하시며, 의의 성읍으로 다시 세우시겠다는 소망의 메시지입니다. 우리의 예배가 삶으로 이어지지 않는다면, 그것은 하나님께서 기뻐하시는 예배가 아닙니다. 오늘 하나님께서 "오라"고 부르십니다. 형식이 아닌 진심으로, 입술이 아닌 삶으로 응답하는 참된 예배자가 되기를 소망합니다.', E'오늘의 핵심\n하나님은 형식적인 종교 행위가 아닌 정의와 공의가 살아있는 참된 예배를 원하시며, 회개하는 자에게는 주홍 같은 죄라도 눈같이 희게 하시는 은혜를 약속하십니다.\n\n묵상 질문\n1. 나의 예배와 일상의 삶 사이에 괴리는 없는지 돌아볼 수 있을까요?\n2. 하나님께서 "오라"고 초청하실 때, 내가 내려놓아야 할 형식적인 신앙의 모습은 무엇일까요?\n3. 오늘 내 주변에서 정의를 구하고 약자를 돌보는 구체적인 실천은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-15', E'이사야의 소명 (이사야 2장)', E'이사야 2장', E'이사야는 어두운 현실 너머에 있는 하나님 나라의 비전을 보여줍니다. "말일에 여호와의 전의 산이 모든 산 꼭대기에 굳게 설 것이요"(사 2:2)라는 말씀처럼, 하나님의 통치가 온 세상 위에 우뚝 서게 될 날이 올 것입니다. 지금은 유다가 우상숭배와 불의로 가득하지만, 하나님께서는 당신의 백성에게 소망의 미래를 약속하고 계십니다.\n\n그 날이 오면 놀라운 변화가 일어납니다. 만방의 백성들이 자발적으로 여호와의 산으로 모여들 것입니다. 그들은 억지로 끌려오는 것이 아니라 "오라 우리가 여호와의 산에 오르자"며 서로를 격려하며 나아옵니다. 무엇이 그들을 그토록 간절하게 만들까요? 바로 하나님의 말씀에 대한 갈망입니다. 시온에서 나오는 율법과 예루살렘에서 나오는 여호와의 말씀을 배우고자 하는 열망이 그들을 움직이게 합니다.\n\n더욱 놀라운 것은 이 하나님의 통치가 가져올 평화의 모습입니다. 칼을 쳐서 보습을 만들고 창을 쳐서 낫을 만든다는 것은 단순히 전쟁이 끝나는 것 이상을 의미합니다. 파괴의 도구가 생명을 살리는 도구로 변화되는 것처럼, 하나님의 나라에서는 근본적인 변혁이 일어납니다. 더 이상 전쟁을 연습하지 않는다는 것은 평화가 일시적이 아니라 영구적임을 보여줍니다.\n\n그러나 현실로 돌아오면 유다의 상황은 정반대입니다. 동방의 미신적 풍속이 가득하고, 이방인들과 손잡고 우상을 섬기며, 물질적 풍요를 자랑하면서도 영적으로는 텅 비어있습니다. 은금과 마필과 병거가 가득하지만, 그것들이 오히려 하나님을 떠나게 만드는 걸림돌이 되었습니다. 스스로의 힘을 의지하며 교만해진 백성들에게 이사야는 경고합니다. 여호와의 날이 임하면 모든 교만한 것들이 낮아지고, 오직 하나님만 높임을 받으실 것입니다.\n\n우리는 어떻습니까? 하나님 나라의 비전을 품고 살아가고 있습니까? 아니면 여전히 세상의 힘과 물질을 의지하며 살고 있습니까? 이사야는 "야곱 족속아 오라 우리가 여호와의 빛에 행하자"고 초청합니다. 미래의 영광스러운 비전은 오늘 우리가 어떻게 살아야 하는지를 보여주는 나침반입니다. 전쟁의 도구를 평화의 도구로 바꾸시는 하나님의 능력이 우리의 삶 속에서도 나타나기를 기대하며, 오늘도 그분의 빛 가운데 걸어가시기 바랍니다.', E'오늘의 핵심\n이사야는 현재의 어두운 현실과 대조되는 하나님 나라의 영광스러운 비전을 제시하면서, 교만과 우상숭배를 버리고 여호와의 빛 가운데 행하도록 초청합니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 의지하고 있는 ''은금과 마필''은 무엇인가요?\n2. 칼을 보습으로 바꾸시는 하나님의 평화가 필요한 내 삶의 영역은 어디인가요?\n3. 하나님의 말씀을 갈망하며 그분께 나아가는 열망이 내 안에 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-16', E'이사야의 소명 (이사야 3장)', E'이사야 3장', E'하나님께서 심판의 칼을 빼드셨습니다. 예루살렘과 유다가 의지하던 모든 것들이 사라질 것입니다. 양식과 물같은 기본적인 것부터 용사와 재판관, 선지자와 장로 같은 지도자들까지, 사회를 지탱하던 모든 기둥이 무너집니다. 더 충격적인 것은 그 자리를 "소년들"과 "아이들"이 채우게 된다는 선언입니다. 이는 단순히 나이가 어리다는 뜻이 아니라, 성숙하지 못하고 책임감 없는 지도력이 등장한다는 의미입니다. 그 결과 백성이 서로를 학대하고, 아이가 노인에게 교만하게 대하는 무질서한 사회가 됩니다.\n\n이 모든 심판의 원인을 하나님은 분명히 밝히십니다. "그들의 언어와 행위가 여호와를 거역하여 그의 영광의 눈을 범하였음이라"(사 3:8). 특별히 하나님은 지도자들의 죄를 엄중히 다루십니다. 백성의 장로들과 고관들이 포도원을 삼키고, 가난한 자들에게서 탈취한 물건으로 자기 집을 채웠습니다. "어찌하여 너희가 내 백성을 짓밟으며 가난한 자의 얼굴에 맷돌질하느냐"라는 하나님의 물음은 사회적 약자를 향한 그분의 특별한 관심을 보여줍니다.\n\n이어서 하나님은 시온의 딸들, 곧 예루살렘 여인들의 교만함을 지적하십니다. 늘인 목과 정을 통하는 눈, 온갖 화려한 장신구로 치장한 그들의 모습은 겉치레에만 몰두하는 당시 사회의 영적 공허함을 상징합니다. 하나님은 이 모든 화려함이 수치로 바뀔 것이며, 향기 대신 썩은 냄새가, 아름다운 머리털 대신 대머리가 될 것이라고 선언하십니다. 이는 단순한 외모의 변화가 아니라 그들이 의지하던 모든 영광과 자랑이 무너지는 철저한 심판입니다.\n\n오늘날 우리는 무엇을 의지하며 살아갑니까? 물질인가요, 지위인가요, 아니면 외모와 능력인가요? 이사야를 통해 하나님은 그 모든 것이 한순간에 사라질 수 있음을 경고하십니다. 특히 지도자의 위치에 있는 이들에게는 더 엄중한 책임을 물으십니다. 약자를 돌보라고 맡겨진 권력으로 오히려 그들을 짓밟는다면, 하나님의 심판을 피할 수 없습니다. 화려한 겉모습 뒤에 숨은 우리의 진짜 모습은 어떠한지, 하나님의 영광의 눈 앞에서 솔직히 돌아봐야 할 때입니다.', E'오늘의 핵심\n하나님은 예루살렘과 유다의 지도자들과 백성들이 의지하던 모든 것을 제거하시고, 특히 약자를 억압하고 겉치레에만 몰두하는 그들의 죄를 철저히 심판하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 것은 무엇이며, 그것이 사라진다면 나는 어떻게 될까요?\n2. 나에게 주어진 권한이나 영향력을 약자를 돕는 일에 사용하고 있나요, 아니면 나의 유익을 위해서만 쓰고 있나요?\n3. 겉으로 보이는 신앙생활과 실제 삶의 모습 사이에 어떤 차이가 있는지 정직하게 점검해볼 필요는 없을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-17', E'이방 나라들에 대한 경고 (이사야 13장)', E'이사야 13장', E'이사야가 받은 첫 번째 열방 심판의 예언은 바벨론을 향합니다. 당시 바벨론은 아직 앗수르의 지배 아래 있던 도시였지만, 하나님께서는 이미 그들이 장차 세계 제국으로 부상할 것과 그 교만으로 인한 멸망까지 내다보고 계셨습니다. 이사야는 하나님께서 "거룩하게 구별한 자들"과 "나의 위엄을 기뻐하는 용사들"을 부르시어 바벨론을 심판하실 것을 선포합니다. 여기서 주목할 점은 하나님께서 이방 민족들까지도 당신의 심판 도구로 사용하신다는 사실입니다. 훗날 바벨론을 멸망시킬 메대와 바사가 바로 그들입니다.\n\n"여호와의 날"이 임할 때 나타날 우주적 혼란의 모습은 창조 질서가 뒤집히는 듯한 공포를 자아냅니다. 해와 달과 별들이 빛을 잃고, 땅이 흔들리며, 사람들이 해산하는 여인처럼 고통스러워하는 장면은 하나님의 심판이 얼마나 철저한지를 보여줍니다. 특히 하나님께서는 "교만한 자의 오만을 끊으며 강포한 자의 거만을 낮출 것"(사 13:11)이라고 말씀하시는데, 이는 바벨론의 죄가 무엇보다 그들의 교만에 있음을 드러냅니다.\n\n한때 "열국의 영광"이요 "갈대아 사람의 자랑"이었던 바벨론이 소돔과 고모라처럼 완전히 황폐해질 것이라는 예언은 실제로 성취되었습니다. 바벨론의 폐허에는 들짐승만이 거하게 되었고, 그 영화는 영원히 사라졌습니다. 이 예언을 통해 하나님께서는 남유다에게 중요한 교훈을 주십니다. 지금 의지하는 앗수르도, 미래에 등장할 바벨론도 결국 하나님의 심판을 피할 수 없다는 것입니다. 오직 역사의 주관자이신 하나님만을 신뢰해야 한다는 메시지가 이 예언의 핵심입니다.', E'오늘의 핵심\n하나님께서는 미래에 세계 제국이 될 바벨론의 흥망성쇠를 미리 보시고, 그들의 교만이 반드시 심판받을 것임을 선포하십니다.\n\n묵상 질문\n1. 하나님께서 이방 민족도 당신의 도구로 사용하신다는 사실이 내게 어떤 의미로 다가오나요?\n2. 내 삶에서 하나님보다 더 의지하고 자랑하는 ''바벨론''은 무엇인가요?\n3. 교만이 가져올 결과를 알면서도 여전히 겸손하지 못한 내 모습을 어떻게 바꿀 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-18', E'이방 나라들에 대한 경고 (이사야 14장)', E'이사야 14장', E'이사야 선지자는 이스라엘의 회복과 바벨론의 몰락을 대조적으로 그려냅니다. 여호와께서 야곱을 긍휼히 여기시고 이스라엘을 다시 택하여 그들의 땅으로 돌아오게 하실 것이며, 오히려 그들을 억압했던 민족들이 이스라엘을 섬기게 될 것이라는 놀라운 역전의 약속이 주어집니다. 이것은 단순한 정치적 복권이 아니라 하나님의 긍휼과 신실하심에 기초한 언약적 회복입니다.\n\n본문의 중심에는 바벨론 왕의 몰락을 노래하는 조롱시가 자리합니다. "너 아침의 아들 계명성이여 어찌 그리 하늘에서 떨어졌으며"(사 14:12)라는 탄식은 교만의 극치를 보여줍니다. 바벨론 왕은 하늘에 올라 하나님의 별들 위에 자리를 높이겠다고 자만했지만, 결국 스올의 맨 밑바닥으로 떨어지고 맙니다. 이는 피조물이 창조주의 자리를 넘보는 것이 얼마나 어리석은 일인지를 극명하게 보여줍니다.\n\n하나님께서는 바벨론뿐 아니라 앗수르와 블레셋에 대한 심판도 선포하십니다. 특히 앗수르를 "나의 땅에서" 파하시겠다는 표현은 의미심장합니다. 앗수르가 아무리 강대해도 결국 하나님의 주권 아래 있으며, 하나님의 백성을 괴롭히는 멍에는 반드시 제거될 것입니다. 이 모든 일이 "만군의 여호와께서 경영하셨은즉" 반드시 이루어질 것이라는 확신은 고난 중에 있는 하나님의 백성에게 큰 위로가 됩니다.\n\n본문은 역사의 주관자이신 하나님의 절대 주권을 선포합니다. 인간의 교만은 아무리 높아 보여도 결국 무너지며, 하나님의 계획은 그 누구도 폐하거나 돌이킬 수 없습니다. 압제당하는 자들에게는 희망을, 교만한 자들에게는 경고를 주시는 하나님의 공의로운 통치가 우리 시대에도 여전히 유효함을 기억해야 합니다.', E'오늘의 핵심\n하나님께서는 교만한 바벨론과 열강들을 심판하시고 고난받는 이스라엘을 회복시키실 것이며, 그 누구도 하나님의 주권적 계획을 막을 수 없습니다.\n\n묵상 질문\n1. 바벨론 왕처럼 하나님의 자리를 넘보는 교만이 내 안에는 없나요?\n2. 고난 중에도 하나님의 긍휼과 회복의 약속을 신뢰하고 있나요?\n3. 역사를 주관하시는 하나님의 절대 주권을 인정하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-20', E'이방 나라들에 대한 경고 (이사야 15장)', E'이사야 15장', E'이사야는 모압의 멸망을 예언하며 하나님의 심판이 얼마나 철저하고 신속할지를 보여줍니다. "하룻밤에" 모압의 주요 도시들이 황폐하게 될 것이라는 표현은 심판의 급작스러움과 완전함을 드러냅니다. 모압 사람들은 그들이 섬기던 신들의 산당에 올라가 울부짖지만, 우상들은 아무런 도움도 주지 못합니다. 대신 그들은 전통적인 애도의 표현인 머리를 밀고 수염을 깎으며, 굵은 베옷을 입고 거리와 지붕에서 통곡합니다.\n\n모압의 비극은 도시에서 도시로, 헤스본과 엘르알레에서 야하스까지 퍼져나갑니다. 군사들조차 두려움에 떨며 부르짖는 모습은 한때 강성했던 나라가 얼마나 무력하게 무너지는지를 보여줍니다. 피난민들은 남쪽 끝 소알까지 도망치지만, 그곳에서도 안전을 찾지 못합니다. 니므림의 물이 마르고 초목이 시들어버린 것처럼, 모압의 생명력 자체가 고갈되어 갑니다.\n\n특별히 주목할 것은 이사야가 "내 마음이 모압을 위하여 부르짖는도다"라고 고백하는 부분입니다. 하나님의 예언자는 심판을 선포하면서도 멸망당할 백성들을 향한 깊은 연민을 품고 있습니다. 이는 하나님 자신의 마음을 반영하는 것으로, 심판 가운데서도 긍휼을 잃지 않으시는 하나님의 성품을 보여줍니다.\n\n그러나 하나님의 심판은 멈추지 않습니다. 디몬의 물에 피가 가득할 뿐 아니라, 도피한 자들과 남은 자들에게까지 사자를 보내어 심판을 완성하겠다고 선언하십니다. 이는 하나님께서 죄에 대해 얼마나 철저하게 다루시는지를 보여주는 동시에, 하나님의 백성을 괴롭혔던 모압의 운명을 통해 이스라엘에게 경고의 메시지를 전달하고 있는 것입니다.', E'오늘의 핵심\n하나님의 심판은 신속하고 철저하지만, 그 가운데서도 하나님은 멸망당할 백성들을 향한 긍휼의 마음을 품고 계십니다.\n\n묵상 질문\n1. 모압이 우상의 산당에서 울부짖어도 구원받지 못하는 모습을 보며, 나는 진정 무엇을 의지하고 있나요?\n2. 심판을 선포하면서도 모압을 위해 마음 아파하는 이사야처럼, 나는 죄인을 향한 긍휼의 마음을 품고 있나요?\n3. 하나님의 경고를 듣고도 회개하지 않은 모압의 모습에서 어떤 교훈을 받을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-21', E'이방 나라들에 대한 경고 (이사야 16장)', E'이사야 16장', E'모압에 대한 하나님의 심판 선언은 단순한 멸망의 예고가 아니라 하나님의 공의와 긍휼이 함께 드러나는 복합적인 메시지입니다. 이사야는 모압이 다가올 환난 때에 유다에게 도움을 청하는 모습을 예언합니다. "너희는 이 땅 통치자에게 어린 양들을 드리되"(사 16:1)라는 말씀은 모압이 조공을 바치며 유다의 보호를 구하는 절박한 상황을 보여줍니다. 아르논 나루에서 떠다니는 새처럼 보금자리를 잃은 모압 백성들의 처지는 교만했던 그들이 얼마나 철저히 무너질 것인지를 암시합니다.\n\n그런데 놀랍게도 하나님은 유다 백성들에게 도망온 모압 난민들을 보호하라고 명령하십니다. 쫓겨난 자들을 숨기고 피할 곳이 되어주라는 이 말씀은, 원수였던 모압에 대해서도 긍휼을 베풀기를 원하시는 하나님의 마음을 드러냅니다. 더 나아가 다윗의 왕위가 인자함으로 굳게 설 것이며, 그 왕이 공의로 다스릴 것이라는 메시아적 소망까지 제시됩니다. 이는 심판 가운데서도 구원의 길을 열어두시는 하나님의 은혜를 보여줍니다.\n\n모압이 심판받는 이유는 그들의 교만 때문이었습니다. 하나님은 "우리가 모압의 교만을 들었나니 심히 교만하도다"라고 지적하십니다. 헤스본의 밭과 십마의 포도원이 황폐하게 되고, 즐거움과 기쁨이 사라지는 것은 교만의 결과입니다. 그럼에도 불구하고 이사야가 모압을 위해 울며, 그의 마음이 수금처럼 애통해하는 것은 하나님께서 심판 중에도 품으시는 긍휼의 마음을 대변합니다. 모압이 산당에서 아무리 열심히 기도해도 소용없을 것이라는 선언은, 참된 회개 없는 종교적 행위의 무익함을 가르쳐줍니다. 삼 년 내에 모압의 영화가 사라질 것이라는 구체적인 예언은 하나님의 심판이 확실하며 피할 수 없음을 보여주지만, 동시에 그 심판 가운데서도 긍휼을 베푸시려는 하나님의 마음이 녹아 있습니다.', E'오늘의 핵심\n하나님은 교만한 모압을 심판하시지만, 동시에 그들에게도 긍휼의 문을 열어두시며, 심판 중에도 구원의 소망을 제시하십니다.\n\n묵상 질문\n1. 하나님께서 원수였던 모압 난민들까지 보호하라고 하신 이유는 무엇일까요?\n2. 내 삶에서 교만이 가져온 황폐함은 없는지 돌아볼 수 있을까요?\n3. 심판 중에도 긍휼을 베푸시는 하나님의 마음을 어떻게 본받을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-22', E'이방 나라들에 대한 경고 (이사야 17장)', E'이사야 17장', E'아람 연합군을 막아달라는 남유다의 요청으로 개입한 앗수르는 다메섹을 중심으로 한 아람 왕국을 철저히 파괴합니다. 이사야는 이제 그 다메섹의 멸망을 하나님의 심판으로 선포합니다. "다메섹이 장차 성읍을 이루지 못하고 무너진 무더기가 될 것이라"(사 17:1)는 예언은 단순한 전쟁의 결과가 아니라 하나님의 주권적 통치를 보여주는 것입니다.\n\n그런데 하나님의 심판은 다메섹에만 머물지 않습니다. 아람과 동맹을 맺었던 북이스라엘 역시 그 영광이 쇠하고 황폐하게 될 것임을 예언합니다. 추수 때 이삭을 주워도 겨우 몇 개만 남는 것처럼, 감람나무를 흔들어도 꼭대기에 두세 개의 열매만 남는 것처럼, 북이스라엘에도 극소수의 남은 자만이 있을 것입니다. 이는 하나님께서 당신의 백성이라 할지라도 불순종과 우상숭배에 대해서는 엄중히 심판하신다는 것을 보여줍니다.\n\n그러나 이 심판 가운데서도 소망의 빛이 비칩니다. 살아남은 소수의 사람들이 비로소 자기를 지으신 하나님을 바라보고, 이스라엘의 거룩하신 분을 뵙게 된다는 것입니다. 그들은 더 이상 자기 손으로 만든 제단이나 아세라 상, 태양상을 의지하지 않게 됩니다. 심판을 통해서라도 참된 신앙의 회복이 일어난다는 것은 하나님의 은혜입니다.\n\n이사야는 북이스라엘이 이런 심판을 받게 된 근본 원인을 분명히 지적합니다. 그들이 구원의 하나님을 잊어버리고, 능력의 반석이신 하나님을 마음에 두지 않았기 때문입니다. 대신 이방의 풍습을 따라 기뻐하는 나무를 심고 이방의 종교를 받아들였습니다. 하나님을 떠난 그들의 모든 노력은 결국 근심과 슬픔의 날에 아무것도 남지 않게 될 것입니다.\n\n마지막으로 이사야는 하나님의 백성을 대적하는 열방의 운명을 묘사합니다. 그들이 아무리 바다 파도처럼 거세게 몰려와도, 하나님께서 꾸짖으시면 산의 겨처럼, 폭풍 앞의 티끌처럼 흩어질 것입니다. 저녁에는 두려움을 주던 그들이 아침이 오기 전에 사라져버릴 것입니다. 이것이 하나님의 백성을 괴롭히는 자들의 최후입니다.', E'오늘의 핵심\n하나님께서는 다메섹과 북이스라엘의 심판을 통해 우상숭배의 결과를 보여주시며, 오직 구원의 하나님만을 의지해야 함을 가르치십니다.\n\n묵상 질문\n1. 나는 구원의 하나님보다 눈에 보이는 것들을 더 의지하고 있지는 않나요?\n2. 고난과 심판 속에서도 하나님의 은혜를 발견할 수 있는 영적 눈이 있나요?\n3. 하나님을 대적하는 세상의 거센 물결 앞에서 어떻게 믿음을 지킬 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-23', E'이스라엘의 회복 (이사야 43장)', E'이사야 43장', E'바벨론 포로기를 앞둔 남유다 백성들에게 하나님께서는 놀라운 위로의 메시지를 전하십니다. 야곱과 이스라엘을 창조하시고 지으신 하나님께서 친히 그들을 부르시며 소유권을 선언하십니다. "내가 너를 지명하여 불렀나니 너는 내 것이라"(사 43:1)는 말씀은 하나님과 이스라엘의 관계가 얼마나 친밀하고 확실한지를 보여줍니다.\n\n물과 불이라는 극한의 위험 속에서도 함께하시겠다는 약속은 곧 다가올 바벨론 포로 생활의 고통 속에서도 하나님의 보호하심이 있을 것임을 암시합니다. 이스라엘의 거룩한 이요 구원자이신 하나님께서는 애굽과 구스와 스바를 이스라엘의 속량물로 주실 정도로 그들을 귀하게 여기십니다. 동서남북 사방에서 자손들을 모으시겠다는 약속은 흩어진 백성들을 다시 회복시키시는 하나님의 신실하심을 보여줍니다.\n\n이사야는 출애굽의 구원을 상기시키면서도 "이전 일을 기억하지 말며 옛날 일을 생각하지 말라"고 선포합니다. 이는 과거의 구원보다 더 놀라운 새 일을 행하실 하나님의 계획을 암시하는 것입니다. 광야에 길을 내고 사막에 강을 내시는 새로운 출애굽의 비전이 제시됩니다.\n\n그러나 이스라엘의 현실은 참담합니다. 하나님을 부르지 않고 오히려 괴롭게 여겼으며, 제물과 예배를 소홀히 했습니다. 도리어 그들의 죄가 하나님을 수고롭고 괴롭게 만들었습니다. 그럼에도 불구하고 하나님께서는 "나를 위하여" 그들의 허물을 도말하시고 죄를 기억하지 않으시겠다고 선언하십니다. 이는 하나님의 일방적인 은혜요, 무조건적인 사랑의 표현입니다. 심판이 아닌 구원을, 정죄가 아닌 용서를 선택하시는 하나님의 마음이 이사야의 예언을 통해 뜨겁게 전달되고 있습니다.', E'오늘의 핵심\n창조주 하나님께서는 이스라엘의 배반에도 불구하고 그들을 "내 것"이라 부르시며, 자신을 위하여 그들의 죄를 용서하시고 새로운 구원의 역사를 약속하십니다.\n\n묵상 질문\n1. 하나님께서 "너는 내 것이라" 부르실 때 느껴지는 소속감과 안정감은 무엇입니까?\n2. 나의 죄가 하나님을 수고롭게 하고 있지는 않은지 돌아볼 영역은 무엇인가요?\n3. 하나님께서 나를 위해서가 아닌 "나를 위하여" 용서하신다는 말씀이 주는 위로는 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-24', E'이스라엘의 회복 (이사야 44장)', E'이사야 44장', E'이스라엘을 향한 하나님의 변함없는 사랑이 선포됩니다. 하나님께서는 당신의 백성을 "나의 종 야곱, 내가 택한 여수룬"이라 부르시며 두려워하지 말라고 위로하십니다. 모태에서부터 그들을 지으시고 도우시는 하나님께서는 목마른 자에게 물을 주시고 마른 땅에 시내가 흐르게 하시듯, 그들의 자손에게 성령을 부어주실 것을 약속하십니다. 이 약속은 단순한 물질적 번영을 넘어 영적 갱신과 하나님과의 관계 회복을 의미합니다.\n\n이어지는 말씀에서 하나님은 우상 숭배의 어리석음을 신랄하게 폭로하십니다. 한 나무로 절반은 땔감으로 쓰고 나머지로는 신상을 만들어 경배하는 모습은 우상 숭배가 얼마나 비논리적이고 허망한지를 보여줍니다. 사람의 손으로 만든 것이 어떻게 창조주가 될 수 있겠습니까. 그러나 우상을 섬기는 자들은 영적으로 눈이 멀어 이 간단한 진리도 깨닫지 못합니다.\n\n하나님께서는 당신만이 처음이요 마지막이며, 다른 신이 없음을 분명히 선언하십니다. 더 나아가 "내가 네 허물을 빽빽한 구름 같이, 네 죄를 안개 같이 없이하였으니"라는 놀라운 용서의 선언을 하십니다. 죄로 인해 멀어졌던 백성들에게 하나님은 먼저 손을 내미시며 "내게로 돌아오라"고 초청하십니다. 이것이 하나님의 은혜입니다.\n\n이 구원의 역사는 단순히 이스라엘만을 위한 것이 아닙니다. 하나님은 이방 왕 고레스를 "내 목자"라 부르시며 그를 통해 예루살렘과 성전을 재건하실 계획을 밝히십니다. 만물을 지으신 여호와께서는 인간의 지혜와 계획을 뛰어넘어 당신의 구원 역사를 이루어 가십니다. 하늘과 땅, 산과 숲이 다 함께 노래하라는 선포는 온 창조세계가 하나님의 구속 사역을 기뻐하며 찬양해야 함을 보여줍니다.', E'오늘의 핵심\n하나님께서는 우상 숭배로 멀어진 이스라엘의 죄를 용서하시고, 성령을 부어주시며, 이방 왕을 통해서라도 당신의 구원 계획을 성취하시는 신실하신 분이십니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 의지하는 현대의 우상은 무엇인가요?\n2. "네 죄를 안개 같이 없이하였다"는 말씀이 오늘 나에게 어떤 위로가 되나요?\n3. 하나님의 용서를 경험한 내가 주님께 돌아가는 구체적인 방법은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-25', E'이스라엘의 회복 (이사야 45장)', E'이사야 45장', E'이사야는 놀라운 예언을 선포합니다. 하나님께서 이방 왕 고레스를 당신의 도구로 사용하신다는 것입니다. 페르시아의 고레스 왕은 하나님을 알지도 못하는 이방인이었지만, 하나님께서는 그를 "기름 부음을 받은 자"로 부르십니다. 이는 이스라엘 역사상 전례 없는 일이었습니다. 하나님께서는 고레스의 오른손을 붙들어 열국을 정복하게 하시고, 바벨론의 견고한 성문들을 열어 이스라엘 백성을 해방시키는 도구로 사용하십니다.\n\n이 예언의 핵심은 하나님의 절대 주권입니다. "나는 여호와라 나 외에 다른 이가 없나니 나 밖에 신이 없느니라"(사 45:5)는 선포가 반복되며, 하나님께서 빛과 어둠을, 평안과 환난을 모두 창조하시는 분임을 분명히 합니다. 진흙이 토기장이에게 항변할 수 없듯이, 피조물이 창조주의 계획에 대해 의문을 제기할 수 없음을 강조합니다.\n\n하나님께서는 고레스를 통해 이루실 구원이 단지 이스라엘만을 위한 것이 아님을 보여주십니다. "땅의 모든 끝이여 내게로 돌이켜 구원을 받으라"는 초청은 하나님의 구원이 온 인류를 향한 것임을 드러냅니다. 이방 왕을 통해 이스라엘을 구원하시는 하나님의 방법은 인간의 예상을 뛰어넘는 것이었지만, 이는 오히려 하나님만이 참된 구원자이심을 더욱 분명하게 증거합니다.\n\n우상을 만들고 섬기는 자들의 무지함과 대조되는 하나님의 지혜와 능력이 선명하게 드러납니다. 하나님께서는 숨어 계시는 것 같아도 실제로는 역사를 주관하시며, 당신의 백성을 위한 영원한 구원을 예비하고 계십니다. 이스라엘은 이 하나님으로 말미암아 의롭다 함을 얻고 영원한 구원에 참여하게 될 것입니다.', E'오늘의 핵심\n하나님께서는 이방 왕 고레스까지도 당신의 구원 계획의 도구로 사용하시며, 이를 통해 하나님만이 유일한 창조주이시자 구원자이심을 온 세계에 선포하십니다.\n\n묵상 질문\n1. 하나님께서 예상치 못한 사람이나 상황을 통해 일하신 경험이 있으신가요?\n2. "나 외에 다른 신이 없다"는 하나님의 선포가 내 삶에 어떤 의미로 다가옵니까?\n3. 하나님의 구원 초청이 모든 민족을 향한다는 사실이 나의 선교적 사명에 어떤 도전을 줍니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-27', E'고난 받는 종 (이사야 53장)', E'이사야 53장', E'이사야 선지자는 장차 오실 메시아의 모습을 놀랍도록 선명하게 그려내고 있습니다. 그런데 그 모습은 우리의 기대와는 전혀 다른 것이었습니다. "연한 순 같고 마른 땅에서 나온 뿌리"(사 53:2)라는 표현은 메시아가 화려하거나 위엄 있는 모습이 아니라 보잘것없고 연약한 모습으로 오실 것을 보여줍니다. 실제로 예수님은 작은 시골 마을 나사렛에서 목수의 아들로 태어나셨고, 세상의 권세자들이 아닌 가난한 자들과 병든 자들의 친구가 되셨습니다.\n\n더욱 충격적인 것은 이 종이 받을 고난의 내용입니다. 이사야는 메시아가 멸시와 천대를 받고, 슬픔과 질고를 짊어지며, 찔림과 상함을 당할 것이라고 예언합니다. 그런데 이 모든 고난이 그분 자신의 죄 때문이 아니라 "우리의 허물" 때문이며 "우리의 죄악" 때문이라는 사실이 계속해서 강조됩니다. 특별히 6절은 인간의 본질적인 문제를 적나라하게 드러냅니다. 우리는 모두 길 잃은 양처럼 각자 제 갈 길로 흩어졌지만, 하나님께서는 그 모든 죄의 무게를 한 분에게 지우셨다는 것입니다.\n\n도수장으로 끌려가는 어린 양의 침묵은 십자가를 향해 가시는 예수님의 순종을 미리 보여줍니다. 빌라도 앞에서, 헤롯 앞에서, 조롱하는 군중들 앞에서 예수님은 자신을 변호하지 않으셨습니다. 이는 연약함이 아니라 아버지의 뜻에 대한 완전한 순종이었습니다. 10절은 이 모든 일이 우연히 일어난 것이 아니라 여호와께서 계획하신 일임을 분명히 합니다. 하나님은 자기 아들을 속건제물로 드림으로써 많은 사람을 의롭게 하시는 놀라운 구원의 계획을 성취하셨습니다.\n\n이사야가 그린 고난받는 종의 초상은 700년 후 갈보리 언덕에서 완벽하게 성취되었습니다. 우리가 평화를 누리는 것은 그분이 징계를 받으셨기 때문이며, 우리가 나음을 받은 것은 그분이 채찍에 맞으셨기 때문입니다. 이것이 복음의 핵심이며, 하나님의 사랑의 극치입니다.', E'오늘의 핵심\n고난받는 종 메시아는 우리의 죄와 허물을 대신 짊어지고 십자가에서 죽으심으로써 우리에게 평화와 치유를 가져다주셨습니다. 이것이 하나님의 구원 계획의 중심입니다.\n\n묵상 질문\n1. 내가 기대하는 메시아의 모습과 이사야가 그린 고난받는 종의 모습은 어떻게 다른가요?\n2. "우리는 다 양 같아서 그릇 행하여 각기 제 길로 갔거늘"이라는 말씀이 내 삶에서는 어떻게 나타나고 있나요?\n3. 예수님이 나를 위해 받으신 고난을 묵상할 때, 오늘 내가 드려야 할 감사와 헌신은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-28', E'고난 받는 종 (이사야 54장)', E'이사야 54장', E'포로기를 겪는 이스라엘에게 하나님께서는 놀라운 회복의 약속을 선포하십니다. 이사야는 출산하지 못한 여인의 비유를 통해 현재의 고통과 미래의 영광을 대비시켜 보여줍니다. 바벨론 포로로 끌려간 이스라엘은 마치 남편을 잃고 자녀도 없는 여인과 같았습니다. 그러나 하나님께서는 이런 절망적인 상황에서 오히려 "노래하라"고 명령하십니다. 황폐해진 예루살렘이 다시 많은 백성으로 채워질 것이며, 그 자손들이 열방을 얻을 것이라는 약속이 주어집니다.\n\n특별히 하나님께서는 자신을 이스라엘의 "남편"이자 "구속자"로 계시하십니다. "이는 너를 지으신 이가 네 남편이시라 그의 이름은 만군의 여호와이시며 네 구속자는 이스라엘의 거룩한 이시라"(사 54:5)는 선언은 하나님과 이스라엘의 관계가 단순한 주종 관계가 아닌 사랑의 언약 관계임을 보여줍니다. 포로기라는 징계는 잠시뿐이며, 하나님의 영원한 자비와 긍휼이 그들을 다시 모으실 것입니다.\n\n이 회복의 약속은 노아 언약과 연결되어 더욱 확실해집니다. 하나님께서 다시는 홍수로 땅을 멸하지 않겠다고 맹세하신 것처럼, 이스라엘을 향한 진노도 영원하지 않을 것입니다. 오히려 하나님께서는 보석으로 예루살렘을 재건하시고, 그들의 자녀들에게 평안을 주시며, 모든 대적으로부터 보호하실 것을 약속하십니다. 이는 단순한 물리적 회복을 넘어 영적이고 영원한 구원을 가리키며, 궁극적으로는 메시아를 통한 새 언약의 성취를 바라보게 합니다. 하나님의 신실하심은 우리의 실패보다 크며, 그분의 사랑은 우리의 배반보다 깊습니다.', E'오늘의 핵심\n하나님께서는 포로기의 절망 속에서도 이스라엘을 버리지 않으시고, 영원한 사랑의 언약으로 그들을 회복시키실 것을 약속하십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님께서 "노래하라"고 하신 이유는 무엇일까요?\n2. 하나님을 ''남편''으로, ''구속자''로 부르는 것이 내게 주는 위로는 무엇인가요?\n3. 내 삶의 어떤 영역에서 하나님의 회복의 약속을 붙잡고 믿음으로 나아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-29', E'고난 받는 종 (이사야 55장)', E'이사야 55장', E'이사야 55장은 하나님께서 베푸시는 은혜의 잔치에 대한 초대장입니다. "오호라 너희 모든 목마른 자들아 물로 나아오라 돈 없는 자도 오라"(사 55:1)는 외침으로 시작되는 이 장은 값없이 주시는 구원의 은혜를 생생하게 보여줍니다. 포로 생활의 고통 속에서 지친 이스라엘 백성들에게 하나님은 생명수와 같은 위로의 말씀을 전하십니다.\n\n이 초대는 단순히 물질적인 풍요를 약속하는 것이 아닙니다. 하나님께서는 백성들이 헛된 것에 힘을 쏟고 있음을 지적하시며, 참된 만족은 오직 하나님과의 관계 회복에서 온다는 것을 가르쳐 주십니다. "너희가 어찌하여 양식이 아닌 것을 위하여 은을 달아 주며 배부르게 하지 못할 것을 위하여 수고하느냐"는 물음은 오늘날 우리에게도 동일하게 던져지는 질문입니다.\n\n특별히 주목할 점은 하나님께서 다윗과 맺으신 영원한 언약을 언급하시는 부분입니다. 이 언약은 다윗의 후손을 통해 오실 메시아, 곧 예수 그리스도를 가리키는 것으로, 만민의 인도자요 명령자가 되실 그분을 통해 이방인까지도 구원의 대상이 됨을 보여줍니다. 이는 이사야 53장에서 예언된 고난받는 종의 사역이 가져올 놀라운 결과입니다.\n\n하나님의 생각과 길이 우리와 다르다는 선언은 인간의 제한된 이해력으로는 하나님의 구원 계획을 온전히 파악할 수 없음을 일깨워 줍니다. 그러나 하늘에서 내리는 비와 눈이 반드시 땅을 적시고 열매를 맺게 하듯이, 하나님의 말씀도 헛되이 돌아오지 않고 반드시 그 목적을 이룬다는 확신을 주십니다. 이 약속은 포로에서 돌아올 백성들뿐 아니라, 말씀을 붙드는 모든 시대의 신앙인들에게 주시는 변함없는 소망입니다.', E'오늘의 핵심\n하나님께서는 목마른 영혼들을 값없이 베푸시는 은혜의 잔치로 초대하시며, 그분의 말씀은 반드시 약속된 구원을 성취할 것입니다.\n\n묵상 질문\n1. 내가 양식이 아닌 것을 위해 수고하고 있는 영역은 무엇인가요?\n2. 하나님의 생각과 길이 나와 다를 때, 어떻게 신뢰하며 순종할 수 있을까요?\n3. 오늘 하나님께서 나를 초대하시는 은혜의 자리는 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-30', E'영광이 빠져버린 시온 산성 (미가 1장)', E'미가 1장', E'미가는 이사야와 거의 동시대에 활동한 선지자로, 하나님의 심판이 임박했음을 선포합니다. 그의 예언은 북이스라엘의 수도 사마리아와 남유다의 수도 예루살렘을 향한 하나님의 준엄한 경고로 시작됩니다. "여호와께서 그의 처소에서 나오시고 강림하사 땅의 높은 곳을 밟으실 것이라"(미 1:3)는 선언은 하나님께서 직접 심판자로 나서실 것을 보여줍니다.\n\n미가가 전하는 심판의 이유는 명확합니다. 하나님의 백성이 우상숭배에 빠져 있었기 때문입니다. 특별히 충격적인 것은 이러한 죄악이 변방이 아닌 수도에서 시작되었다는 사실입니다. 사마리아와 예루살렘은 각각 북이스라엘과 남유다의 정치적, 종교적 중심지였습니다. 그런데 바로 그곳이 죄악의 온상이 되어버린 것입니다. 미가는 이를 가리켜 "야곱의 허물이 무엇이냐 사마리아가 아니냐 유다의 산당이 무엇이냐 예루살렘이 아니냐"라고 탄식합니다.\n\n하나님의 심판은 철저할 것입니다. 사마리아는 완전히 파괴되어 들의 무더기처럼 되고, 그들이 섬기던 우상들은 모두 부서질 것입니다. 더욱 비극적인 것은 이 심판이 사마리아에서 그치지 않고 남유다까지 확산될 것이라는 예언입니다. 미가는 이 재앙이 "유다까지도 이르고 내 백성의 성문 곧 예루살렘에도 미쳤음"을 선포합니다.\n\n선지자는 임박한 심판을 바라보며 깊은 애통 가운데 빠집니다. 그는 벌거벗은 몸으로 행하며 들개같이 애곡하고 타조같이 애통하겠다고 말합니다. 이는 단순한 감정의 표현이 아니라 백성을 향한 하나님의 마음을 대변하는 것이었습니다. 미가는 각 성읍들의 이름을 언급하며 그들에게 닥칠 재앙을 구체적으로 묘사하는데, 이는 심판이 얼마나 광범위하고 철저할 것인지를 보여줍니다.\n\n특별히 라기스는 "딸 시온의 죄의 근본"으로 지목됩니다. 라기스는 애굽과 가까운 요새 도시로서 우상숭배가 그곳을 통해 예루살렘으로 유입되었음을 암시합니다. 결국 하나님의 백성은 그들이 기뻐하던 자녀들과 이별하고 포로로 끌려가는 비극을 맞이하게 될 것입니다. 미가의 예언은 하나님을 떠난 백성의 최후가 얼마나 비참한지를 생생하게 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 신앙의 중심지가 오히려 우상숭배의 온상이 된 것을 보시고, 사마리아와 예루살렘에 철저한 심판을 선포하십니다.\n\n묵상 질문\n1. 신앙의 중심이어야 할 곳에서 죄악이 시작되는 것을 보며 어떤 경각심을 갖게 되나요?\n2. 미가처럼 시대의 죄악을 보며 애통해 본 적이 있으신가요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 ''라기스''는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-03-31', E'영광이 빠져버린 시온 산성 (미가 2장)', E'미가 2장', E'미가 선지자가 활동하던 시대는 부익부 빈익빈의 골이 깊어지던 때였습니다. 남유다의 지도층은 밤낮으로 악을 도모하며 힘없는 백성들의 재산을 강탈하는 일을 서슴지 않았습니다. 미가는 이러한 사회적 불의를 향해 하나님의 심판을 선포합니다.\n\n본문은 당시 권력자들의 죄악상을 적나라하게 보여줍니다. 그들은 침상에서조차 죄를 꾀하며 악을 계획했고, 날이 밝으면 곧바로 실행에 옮겼습니다. 남의 밭과 집을 탐내어 빼앗고, 사람과 그의 산업을 강탈하는 일이 일상이 되어버렸습니다. 이는 단순한 개인의 탐욕을 넘어 사회 구조적인 악이 되어가고 있었음을 보여줍니다.\n\n하나님께서는 이러한 불의에 대해 재앙을 선포하십니다. 그들이 남의 것을 빼앗았듯이, 하나님께서도 그들의 산업을 빼앗아 패역자에게 주시겠다고 말씀하십니다. 특히 주목할 것은 백성들이 하나님의 경고를 거부하며 "예언하지 말라"고 외치는 모습입니다. 그들은 자신들에게 유리한 거짓 선지자들의 달콤한 말만을 듣기 원했습니다.\n\n그러나 하나님의 공의는 결코 막을 수 없습니다. 미가는 전쟁을 피해 평안히 지나가는 자들의 겉옷을 벗기고, 부녀자들을 집에서 쫓아내며, 어린 자녀들에게서 하나님의 영광을 빼앗는 그들의 죄악을 낱낱이 고발합니다. 이는 단지 재산의 문제가 아니라 인간의 존엄성과 하나님의 영광을 훼손하는 일이었습니다.\n\n그럼에도 불구하고 본문의 마지막은 희망으로 마무리됩니다. 하나님께서는 흩어진 이스라엘의 남은 자들을 다시 모으시고, 목자가 양떼를 인도하듯 친히 그들의 왕이 되어 앞서 가시겠다고 약속하십니다. 심판 가운데서도 회복의 소망을 잃지 않으시는 하나님의 사랑이 여기에 나타납니다.', E'오늘의 핵심\n하나님께서는 가난한 자를 억압하고 약자를 착취하는 사회적 불의를 결코 용납하지 않으시며, 공의로운 심판과 함께 회복의 소망도 약속하십니다.\n\n묵상 질문\n1. 나는 혹시 나의 이익을 위해 다른 사람에게 해를 끼치고 있지는 않나요?\n2. 하나님의 말씀이 불편할 때, 나는 어떤 태도를 취하고 있나요?\n3. 오늘날 우리 사회에서 하나님의 공의가 필요한 영역은 어디일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-01', E'영광이 빠져버린 시온 산성 (미가 3장)', E'미가 3장', E'미가 선지자는 예루살렘의 지도자들을 향해 날카로운 심판의 메시지를 전합니다. 야곱의 우두머리들과 이스라엘 족속의 통치자들이 정의를 알아야 할 본분을 저버리고, 오히려 선을 미워하고 악을 기뻐하는 모습을 하나님께서는 참혹한 비유로 묘사하십니다. 백성의 가죽을 벗기고 뼈에서 살을 뜯어 먹는다는 표현은 권력자들이 얼마나 잔인하게 백성들을 착취하고 있는지를 생생하게 보여줍니다.\n\n이러한 악행은 정치 지도자들에게만 국한되지 않았습니다. 선지자들은 뇌물을 받으면 평강을 외치고, 그렇지 않으면 전쟁을 준비한다고 선포했습니다. 제사장들은 삯을 위해 교훈했고, 예언자들은 돈을 위해 점을 쳤습니다. 종교 지도자들마저 하나님의 말씀을 상품화하고 자신들의 이익을 위해 진리를 왜곡했던 것입니다. 그러면서도 그들은 "여호와께서 우리 중에 계시지 아니하냐 재앙이 우리에게 임하지 아니하리라"(미 3:11)고 말하며 거짓된 안전감에 빠져 있었습니다.\n\n이런 상황에서 미가는 여호와의 영으로 충만하여 능력과 정의와 용기로 야곱의 허물과 이스라엘의 죄를 드러냅니다. 그는 시온이 피로, 예루살렘이 죄악으로 건축되고 있음을 선포합니다. 하나님의 도성이어야 할 예루살렘이 백성들의 고혈을 짜내어 세워진 불의의 도시가 되어버린 것입니다. 미가의 예언대로 시온은 갈아엎은 밭이 되고, 예루살렘은 무더기가 되며, 성전의 산은 수풀의 높은 곳이 될 것입니다. 이는 단순한 물리적 파괴를 넘어 하나님과의 관계가 완전히 단절됨을 의미합니다. 정의와 공의를 버린 채 종교적 형식만 남은 예배는 하나님께서 받으실 수 없는 것임을 미가서는 분명히 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 백성을 착취하는 지도자들과 돈을 위해 진리를 왜곡하는 종교 지도자들의 죄악을 드러내시며, 불의로 세워진 예루살렘에 대한 심판을 선포하십니다.\n\n묵상 질문\n1. 오늘날 우리 사회와 교회 안에서 정의를 외면하고 자기 이익만을 추구하는 모습은 없는지 돌아보셨나요?\n2. 하나님의 이름으로 안전감을 느끼면서도 실제로는 불의를 행하는 이중적인 모습이 내 안에 있지는 않나요?\n3. 미가처럼 하나님의 영으로 충만하여 불의를 지적할 용기와 정의를 실천할 힘을 구하고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-03', E'마음을 찢으라 (요한1서 1장)', E'요한1서 1장', E'사도 요한은 복음서를 기록한 후 말년에 이르러, 교회 공동체를 향해 깊은 목회적 관심을 담은 서신을 남깁니다. 당시 초대교회는 예수 그리스도의 성육신을 부인하는 영지주의적 가르침으로 인해 혼란을 겪고 있었습니다. 이러한 상황에서 요한은 자신이 직접 보고 들었던 생명의 말씀, 곧 영원한 생명이신 예수 그리스도를 증언합니다. 그는 단순히 관념적인 진리가 아닌, 역사 속에 실제로 나타나신 분을 전하고 있는 것입니다.\n\n요한이 이 서신을 쓰는 목적은 분명합니다. 그것은 성도들이 아버지 하나님과 그의 아들 예수 그리스도와 참된 사귐을 누리도록 하기 위함입니다. 이 사귐은 단지 종교적 의무나 형식이 아닌, 생명적이고 인격적인 관계를 의미합니다. 그리고 이러한 사귐이 있을 때 비로소 충만한 기쁨을 경험할 수 있다고 요한은 전합니다.\n\n특별히 요한은 하나님의 본질을 "빛"으로 계시하면서, 그분 안에는 어둠이 조금도 없으심을 선포합니다. 이는 우리가 어떻게 살아야 하는지를 보여주는 중요한 기준이 됩니다. 빛 되신 하나님과 사귐을 가지면서 동시에 어둠 가운데 행할 수는 없기 때문입니다. 진정한 사귐은 빛 가운데 행하는 삶으로 나타나며, 이때 예수님의 보혈이 우리를 모든 죄에서 깨끗하게 하신다는 놀라운 약속이 주어집니다.\n\n그러나 요한은 현실적인 문제도 직시합니다. 우리가 죄가 없다고 주장하는 것은 자기 기만이며, 하나님을 거짓말하는 이로 만드는 것입니다. 오히려 우리가 죄를 자백할 때, 미쁘시고 의로우신 하나님께서 우리를 용서하시고 모든 불의에서 깨끗하게 하십니다. 이것이 바로 은혜의 복음이며, 빛 가운데 거하는 삶의 시작점입니다.', E'오늘의 핵심\n빛이신 하나님과의 참된 사귐은 우리가 빛 가운데 행할 때 가능하며, 죄를 자백하는 정직함을 통해 그리스도의 보혈로 깨끗함을 받는 은혜의 삶으로 인도됩니다.\n\n묵상 질문\n1. 나는 하나님과의 사귐을 종교적 의무가 아닌 생명적 관계로 경험하고 있나요?\n2. 빛 가운데 행한다고 하면서도 여전히 붙잡고 있는 어둠의 영역은 무엇인가요?\n3. 오늘 하나님께 정직하게 자백해야 할 죄는 무엇이며, 그분의 용서를 어떻게 받아들일 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-04', E'마음을 찢으라 (요한1서 2장)', E'요한1서 2장', E'요한은 그리스도인들이 죄를 범하지 않도록 권면하면서도, 동시에 우리의 연약함을 아시는 하나님의 은혜를 전합니다. 그리스도께서 우리의 대언자가 되시며 화목제물이 되셨다는 복음의 핵심은, 단지 우리만을 위한 것이 아니라 온 세상을 위한 것입니다. 이는 하나님의 구원 계획이 얼마나 광대한지를 보여줍니다.\n\n참된 믿음의 증거는 하나님의 계명을 지키는 것으로 나타납니다. 요한은 말과 행동이 일치하지 않는 신앙의 위험성을 경고하면서, 그리스도 안에 거하는 자는 그분이 행하신 대로 행해야 한다고 가르칩니다. 특별히 형제 사랑의 계명은 새로우면서도 옛 것으로, 빛 가운데 행하는 자의 필수적인 표지입니다. 형제를 미워하면서 빛 가운데 있다고 하는 것은 자기기만일 뿐입니다.\n\n요한은 다양한 연령대의 신앙인들에게 각각의 영적 성숙도에 맞는 권면을 전합니다. 죄 사함을 받은 자녀들, 하나님을 깊이 아는 아비들, 악한 자를 이긴 청년들 모두에게 세상과 그 정욕을 사랑하지 말라고 당부합니다. 육신의 정욕, 안목의 정욕, 이생의 자랑은 일시적이지만, 하나님의 뜻을 행하는 자는 영원히 거합니다.\n\n마지막 때의 징조로 많은 적그리스도가 일어났음을 언급하면서, 요한은 교회 공동체에서 떠나간 자들의 정체를 밝힙니다. 그들은 처음부터 진정으로 속하지 않았기에 떠난 것입니다. 반면 참된 성도들은 거룩하신 분에게서 기름부음을 받아 진리를 알며, 그리스도를 부인하지 않습니다. 처음부터 들은 복음의 진리 안에 거하는 것이 영원한 생명의 약속을 누리는 길입니다.', E'오늘의 핵심\n그리스도 안에 거하는 참된 신앙은 형제 사랑의 실천과 세상 정욕을 거부하는 거룩한 삶으로 증명되며, 이는 영원한 생명으로 인도합니다.\n\n묵상 질문\n1. 나는 하나님을 안다고 말하면서도 그분의 계명을 소홀히 여기고 있지는 않나요?\n2. 형제를 미워하면서도 빛 가운데 있다고 착각하는 영적 맹목 상태는 아닌지 점검해 보셨나요?\n3. 일시적인 세상의 정욕과 영원한 하나님의 뜻 사이에서 오늘 무엇을 선택하겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-05', E'마음을 찢으라 (요한1서 3장)', E'요한1서 3장', E'사도 요한은 하나님의 자녀된 신분의 영광과 그에 따른 삶의 변화를 깊이 있게 조명합니다. "보라 아버지께서 어떠한 사랑을 우리에게 베푸사 하나님의 자녀라 일컬음을 받게 하셨는가"(요일 3:1)라는 감탄은 구원받은 자의 놀라운 신분 변화를 보여줍니다. 세상이 우리를 알지 못하는 이유는 세상이 하나님을 알지 못하기 때문입니다. 이는 하나님의 자녀들이 세상과는 다른 가치관과 삶의 방식을 갖게 되었음을 의미합니다.\n\n하나님의 자녀된 신분은 현재의 축복일 뿐 아니라 미래의 소망이기도 합니다. 장래에 어떻게 될지는 아직 완전히 나타나지 않았지만, 그리스도께서 재림하실 때 우리가 그분과 같이 될 것이며, 그분의 참모습을 볼 것입니다. 이러한 소망은 현재의 삶을 거룩하게 만드는 원동력이 됩니다. 주를 향한 소망을 가진 자는 그리스도의 깨끗하심을 본받아 자신을 깨끗하게 합니다.\n\n요한은 하나님의 자녀와 마귀의 자녀를 구별하는 두 가지 표지를 제시합니다. 첫째는 의를 행하는 것이고, 둘째는 형제를 사랑하는 것입니다. 하나님께로부터 난 자는 하나님의 씨가 그 안에 거하므로 죄를 짓지 않습니다. 이는 완전무결함을 의미하는 것이 아니라, 죄를 습관적으로 행하지 않으며 죄와 싸우는 삶을 산다는 뜻입니다.\n\n특별히 형제 사랑은 그리스도인의 본질적 표지입니다. 그리스도께서 우리를 위하여 목숨을 버리신 것처럼, 우리도 형제를 위하여 희생하는 사랑을 실천해야 합니다. 이 사랑은 말과 혀로만이 아니라 행함과 진실함으로 나타나야 합니다. 세상의 재물을 가지고도 궁핍한 형제를 돕지 않는다면, 하나님의 사랑이 그 안에 거한다고 할 수 없습니다.\n\n하나님의 계명은 그 아들 예수 그리스도를 믿고 서로 사랑하는 것입니다. 이 계명을 지키는 자는 주 안에 거하고, 주께서도 그 안에 거하십니다. 성령께서 우리 안에 거하시는 증거로 우리는 하나님과의 친밀한 교제를 누리며, 담대히 하나님께 나아갈 수 있습니다.', E'오늘의 핵심\n하나님의 자녀된 우리는 그리스도를 닮아가는 거룩한 삶과 형제를 향한 희생적 사랑을 통해 그 정체성을 드러내야 합니다.\n\n묵상 질문\n1. 하나님의 자녀라는 놀라운 신분이 내 삶에 어떤 변화를 가져왔나요?\n2. 나는 말과 혀로만이 아니라 행함과 진실함으로 형제를 사랑하고 있나요?\n3. 내 안에 거하시는 성령님의 임재를 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-06', E'남유다에 대한 설득과 심판', E'예레미야 13장', E'요시야가 애굽과의 싸움인 므깃도 전투에서 전사하자 백성은 요시야의 둘째 아들 여호아하스를 왕으로 삼았습니다. 하지만 여호아하스는 3개월 만에 애굽 왕 느고에게 잡혀 애굽으로 끌려가고 뒤를 이어 요시야의 큰아들 여호야김이 왕위에 오릅니다. 여호야김은 왕위에 오른 후 3년간 바빌론에 조공을 바치다가 중단합니다. 그러자 바빌론의 느부갓네살이 이에 대한 보복으로 예루살렘에 올라와 여호와의 성전 기구들을 바벨론으로 가져갑니다. 이때 끌려간 사람들이 다니엘을 비롯한 1차 바벨론 포로입니다(B.C.605). 그 후, 여호야김의 아들 여호야긴이 왕이 되자 느부갓네살이 또다시 예루살렘으로 와서 여호야긴은 물론, 나라의 권세 있는 자들을 모두 잡아갑니다. 이것이 2차 바벨론 포로(B.C.598)입니다. 그리고 남유다 땅에 남은 백성을 다스릴 자로 요시야의 막내아들인 맛다니야(시드기야)가 세워집니다. 그가 바로 남유다의 마지막 왕입니다.\n한편, 오랜 세월 동안 하나님의 경고를 무시해온 예루살렘을 향한 심판은 이미 결정되었고, 선지자 예레미야가 부름을 받습니다. 예레미야에게는 남유다의 멸망과 70년간의 포로 생활을 예언해야 하는 힘든 사명이 주어졌습니다.', E'오늘의 핵심\n심판이 확정되어 멸망의 문에 점점 다가서고 있는 남유다에 예레미야가 마지막 설득을 위해 보냄을 받습니다.\n\n묵상 질문\n하나님은 왜 계속해서 회개의 기회를 주셨을까요?\n내가 하나님 말씀에 불순종할 때 어떤 결과를 마주하고 있나요?\n오늘 말씀 속에서 하나님께 돌아가야 할 나의 모습은 무엇인가요?');
